-- ==========================================
-- INITIALIZE SCHEMAS
-- ==========================================

    -- 1. Wipe existing tables clean to prevent schema conflicts
    DROP TABLE IF EXISTS denominations;
    DROP TABLE IF EXISTS questions;
    DROP TABLE IF EXISTS answer_options;
    DROP TABLE IF EXISTS denomination_answers;
    DROP TABLE IF EXISTS denomination_selected_options;
    DROP TABLE IF EXISTS denomination_compass_coordinates;
    DROP TABLE IF EXISTS hidden_dimensions;
    DROP TABLE IF EXISTS answer_scoring;

    -- 2. Recreate tables with correct schemas
    CREATE TABLE denominations (id TEXT PRIMARY KEY, name TEXT, family TEXT, founded_year TEXT, region_origin TEXT, description TEXT);
    
    CREATE TABLE questions (
        id TEXT PRIMARY KEY, 
        category_code TEXT, 
        priority_score REAL, 
        full_text TEXT,
        include_quick INTEGER,
        display_order_quick REAL,
        include_standard INTEGER,
        display_order_standard REAL,
        include_deep INTEGER,
        display_order_deep REAL
    );
    
    CREATE TABLE answer_options (id TEXT PRIMARY KEY, question_id TEXT, answer_text TEXT, theological_label TEXT, description TEXT);
    
    CREATE TABLE denomination_answers (denomination_id TEXT, question_id TEXT, certainty REAL, tolerance REAL, PRIMARY KEY (denomination_id, question_id));
    
    CREATE TABLE denomination_selected_options (denomination_id TEXT, question_id TEXT, answer_text TEXT);
    
    CREATE TABLE denomination_compass_coordinates (denomination_id TEXT, mode TEXT, tolerance_score REAL, theol_cons_lib_avg REAL, social_cons_lib_avg REAL, counter_pro_modern_avg REAL, super_nat_avg REAL, cult_sep_eng_avg REAL, cleric_egal_avg REAL, div_hum_agency_avg REAL, commun_indiv_avg REAL, liturg_spont_avg REAL, sacram_funct_avg REAL, literal_crit_avg REAL, intellect_exper_avg REAL, PRIMARY KEY (denomination_id, mode));
    
    CREATE TABLE hidden_dimensions (question_id TEXT PRIMARY KEY, theol_cons_lib REAL, social_cons_lib REAL, counter_pro_modern REAL, super_nat REAL, cult_sep_eng REAL, cleric_egal REAL, div_hum_agency REAL, commun_indiv REAL, liturg_spont REAL, sacram_funct REAL, literal_crit REAL, intellect_exper REAL);
    
    CREATE TABLE answer_scoring (answer_id TEXT PRIMARY KEY, theol_cons_lib REAL, social_cons_lib REAL, counter_pro_modern REAL, super_nat REAL, cult_sep_eng REAL, cleric_egal REAL, div_hum_agency REAL, commun_indiv REAL, liturg_spont REAL, sacram_funct REAL, literal_crit REAL, intellect_exper REAL);
    
-- ==========================================
-- TABLE: denominations
-- ==========================================
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_001', 'The Apostolic Church (Early Church)', 'Jewish Christianity', 'c. 30 AD', 'Judea (Jerusalem)', 'The original community of Jesus'' followers; initially a sect within Second Temple Judaism practicing temple worship, communal living, and adherence to the Torah while proclaiming Jesus as Messiah.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_002', 'Pauline Communities (Gentile Christianity)', 'Early Christianity', 'c. 40s AD', 'Antioch / Asia Minor / Greece', 'The network of churches established by Paul; characterized by the inclusion of Gentiles without the requirement of circumcision or strict Torah observance, emphasizing justification by faith.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_003', 'Johannine Community', 'Early Christianity', 'c. 90 AD', 'Asia Minor (Ephesus)', 'A distinct network of communities producing the Johannine corpus (Gospel/Epistles); emphasized high Christology (Logos), pneumatic spirituality, and dualistic language (light/dark).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_004', 'Nazarenes', 'Jewish Christianity', 'c. 70 AD', 'Coele-Syria / Pella', 'Jewish Christians who fled Jerusalem to Pella; accepted the Virgin Birth and Paul’s mission (to Gentiles) but continued to observe the Mosaic Law themselves and used a Hebrew/Aramaic Gospel.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_005', 'Ebionites', 'Jewish Christianity', 'c. 100 AD', 'Transjordan / Syria', 'The Poor; a strict Jewish-Christian sect that rejected the Virgin Birth (adoptionist), rejected Paul as an apostate, required vegetarianism and poverty, and emphasized the Law.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_006', 'Elchasaites', 'Gnostic / Jewish Christian', 'c. 100 AD', 'Mesopotamia', 'A syncretic baptist sect emphasizing repeated immersions for sin; blended Jewish Law with Gnostic elements, astrology, and a belief in the cyclic incarnation of the True Prophet.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_007', 'Ante-Nicene Church', 'Catholic / Orthodox', 'c. 180 AD', 'Mediterranean Basin', 'The emerging consensus of the majority church; defined by apostolic succession, the rule of faith, the fourfold Gospel canon, and opposition to Gnosticism; the direct ancestor of modern Catholicism and Orthodoxy.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_008', 'Simonians', 'Gnostic', 'c. 50 AD', 'Samaria', 'Regarded as the first heretical sect by Church Fathers; followers of Simon Magus who allegedly claimed to be the Great Power of God and practiced magic; a precursor to later Gnosticism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_009', 'Cerinthians', 'Gnostic / Jewish Christian', 'c. 100 AD', 'Asia Minor', 'Taught that the Christ spirit descended on the human Jesus at baptism and left before crucifixion; rejected the creator god of the Jews but retained some Jewish observances.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_010', 'Nicolaitans', 'Early Gnostic (Antinomian)', 'c. 90 AD', 'Asia Minor', 'Mentioned in Revelation; an antinomian group that likely taught that spiritual freedom allowed for participation in idolatrous feasts and sexual libertinism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_011', 'Basilideans', 'Gnostic', 'c. 120 AD', 'Alexandria (Egypt)', 'An early sophisticated Gnostic school; taught a complex emanation cosmogony, that the crucifixion was an illusion (Simon of Cyrene died instead), and maintained a vow of silence.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_012', 'Valentinians', 'Gnostic', 'c. 140 AD', 'Rome / Alexandria', 'The most influential and intellectually rigorous Gnostic school; taught a complex myth of the Pleroma (fullness) and Sophia''s fall, interpreting Christian scripture through esoteric allegory.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_013', 'Marcionites', 'Restorationist / Dualist', 'c. 144 AD', 'Rome', 'A massive rival to the Great Church; rejected the Old Testament and its Creator God (Demiurge) as evil/inferior; established the first closed canon (edited Luke + 10 Pauline letters).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_014', 'Sethians', 'Gnostic', 'c. 150 AD', 'Syria / Palestine', 'Classic Gnosticism; revered Seth (son of Adam) as the spiritual ancestor of the enlightened seed; produced texts like the Apocryphon of John depicting the Demiurge Yaldabaoth.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_015', 'Carpocratians', 'Gnostic', 'c. 150 AD', 'Alexandria (Egypt)', 'A libertine Gnostic group; believed Jesus was the son of Joseph who transcended the world; taught that one must experience every sin to escape the cycle of reincarnation.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_016', 'Encratites', 'Ascetic / Rigorist', 'c. 170 AD', 'Syria / Mesopotamia', 'The Self-Controlled; rejected marriage, wine (using water for Eucharist), and meat; viewed reproduction as perpetuating the fallen world.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_017', 'Montanists (New Prophecy)', 'Charismatic / Prophetic', 'c. 156 AD', 'Phrygia (Asia Minor)', 'An apocalyptic movement claiming new revelation through the Paraclete; featured female leadership, ecstatic prophecy, and strict moral rigorism; condemned by bishops for bypassing clerical authority.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_018', 'Quartodecimans', 'Early Christianity (Liturgical)', 'c. 150 AD', 'Asia Minor', 'Churches that celebrated Pascha (Easter) on 14 Nisan (Jewish Passover) regardless of the day of the week, claiming authority from John the Apostle; clashed with Rome''s Sunday observance.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_019', 'Alogi', 'Anti-Gnostic', 'c. 170 AD', 'Asia Minor', 'A reactionary group that rejected the Gospel of John and the Apocalypse (Revelation) to counter Montanism and Gnostic Logos theology; denied the Logos doctrine.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_020', 'Theodotians (Dynamic Monarchians)', 'Nontrinitarian (Adoptionist)', 'c. 190 AD', 'Rome / Byzantium', 'Taught that Jesus was a mere man (virtuous) tested by God, upon whom the Spirit descended at baptism; denied Jesus was God by nature (Adoptionism).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_021', 'Sabellians (Modalists)', 'Nontrinitarian (Modalist)', 'c. 215 AD', 'Rome / Libya', 'Believed Father, Son, and Spirit were three modes or masks of one single person (Monad), not distinct persons; accused of Patripassianism (the Father suffered on the cross).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_022', 'Novatianists', 'Schismatic / Rigorist', 'c. 251 AD', 'Rome', 'A Church of the Pure formed after the Decian persecution; refused to readmit the lapsi (those who sacrificed to idols) to communion; theologically orthodox but disciplinary hardliners.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_023', 'Paulianists (Samosatenes)', 'Nontrinitarian (Adoptionist)', 'c. 260 AD', 'Antioch', 'Followers of Paul of Samosata; taught Jesus was a man who became divine through will and union with God''s wisdom/Logos (not a distinct person but an attribute); condemned at Antioch (268).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_024', 'Manichaeans', 'Syncretic Dualist', 'c. 240 AD', 'Sassanid Empire (Persia)', 'A distinct world religion rivaling Christianity; Mani claimed to be the Apostle of Jesus Christ; synthesized Christianity, Zoroastrianism, and Buddhism into a rigorous dualist cosmology.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_025', 'Melitians', 'Schismatic / Rigorist', 'c. 306 AD', 'Egypt', 'A rigorist schism parallel to Donatism; formed over the treatment of lapsed Christians during the Diocletian persecution; allied with Arians against the Bishop of Alexandria.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_026', 'Donatists', 'Schismatic / Rigorist', 'c. 311 AD', 'North Africa (Carthage)', 'Major North African church rejecting traditors (clergy who handed over books during persecution); taught that sacraments are invalid if performed by unworthy priests; distinct Punic social identity.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_027', 'Arians', 'Nontrinitarian (Subordinationist)', 'c. 310 AD', 'Alexandria', 'The central controversy of the 4th century; taught that the Son was a created being (there was when he was not) and not co-eternal or consubstantial with the Father.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_028', 'Borborites', 'Gnostic (Libertine)', 'c. 300s AD', 'Various', 'A pejorative name (Filthy Ones) for a late Gnostic group described by Epiphanius; allegedly practiced sacramental consumption of bodily fluids and extreme antinomianism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_029', 'Audians', 'Anthropomorphic / Rigorist', 'c. 325 AD', 'Syria / Mesopotamia', 'A schismatic group that read image of God literally (Anthropomorphism), believing God has a human form; also quartodeciman in practice and morally rigorist.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_030', 'Messalians (Euchites)', 'Ascetic / Charismatic', 'c. 350s AD (Roots in 3rd C.)', 'Mesopotamia / Syria', 'The Praying Ones; rejected sacraments and hierarchy, believing only ceaseless prayer could expel the indwelling demon present in all humans; precursors to later mysticism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_031', 'Imperial Nicene Church', 'Early Catholic/Orthodox', '325 AD', 'Roman Empire', 'The state-sanctioned church following the Council of Nicaea; established the Nicene Creed and the pentarchy of patriarchates (Rome, Constantinople, Alexandria, Antioch, Jerusalem) before later schisms.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_032', 'Roman Catholic Church (Latin Rite)', 'Catholic (Imperial)', 'c. 30 AD / 1054 AD', 'Rome', 'The largest Christian church; defined by full communion with the Bishop of Rome (Pope), usage of the Latin Rites (mostly), and acceptance of all 21 Ecumenical Councils.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_033', 'Maronite Church', 'Eastern Catholic (West Syriac)', 'c. 350 AD', 'Lebanon (Mount Lebanon)', 'The only Eastern church that has no Orthodox counterpart (never formally severed communion with Rome); uses the West Syriac Rite and maintains a distinct monastic-patriarchal identity.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_034', 'Syro-Malabar Church', 'Eastern Catholic (East Syriac)', '52 AD / 1599 AD', 'Kerala (India)', 'St. Thomas Christians who affirmed communion with Rome at the Synod of Diamper; uses the East Syriac (Chaldean) liturgy but deeply indigenous to Indian culture.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_035', 'Ukrainian Greek Catholic Church', 'Eastern Catholic (Byzantine)', '1596 AD', 'Kyiv (Ukraine)', 'The largest Eastern Catholic church; formed by the Union of Brest where Orthodox bishops in Polish-Lithuanian Commonwealth accepted papal primacy while retaining Byzantine rite and married clergy.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_036', 'Chaldean Catholic Church', 'Eastern Catholic (East Syriac)', '1552 AD', 'Mesopotamia (Iraq)', 'Formed from a schism within the Church of the East (Nestorian); entered communion with Rome to secure a patriarchal line; preserves the ancient East Syriac liturgy.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_037', 'Melkite Greek Catholic Church', 'Eastern Catholic (Byzantine)', '1724 AD', 'Damascus / Antioch', 'Melkite (King''s men); Byzantine Christians in the Middle East who split from the Antiochian Orthodox Patriarchate to reaffirm communion with Rome; strongly emphasizes its Arab heritage.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_038', 'Benedictines (Order)', 'Catholic Religious Order', '529 AD', 'Subiaco / Monte Cassino (Italy)', 'The foundational order of Western Monasticism; independent abbeys living under the Rule of St. Benedict (Ora et Labora); historically preserved literacy and agriculture in Europe.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_039', 'Carthusians (Order)', 'Catholic Religious Order', '1084 AD', 'Chartreuse Mountains (France)', 'The most rigorist contemplative order; hermits living in community with near-total silence, solitude, and fasting; Never reformed because never deformed.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_040', 'Cistercians / Trappists (Order)', 'Catholic Religious Order', '1098 AD', 'Cîteaux (France)', 'A reform of Benedictinism emphasizing manual labor, poverty, and seclusion; Trappists (17th C. reform) are famous for strict observance and beer/cheese production.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_041', 'Franciscans (Order)', 'Catholic Religious Order', '1209 AD', 'Assisi (Italy)', 'Mendicant order focused on radical poverty, preaching, and identification with the poor; split into various branches (Observants, Capuchins, Conventuals) over the strictness of poverty.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_042', 'Dominicans (Order)', 'Catholic Religious Order', '1216 AD', 'Toulouse (France)', 'Mendicant order dedicated to preaching and combating heresy through intellectual rigor; dominated scholastic theology and the Inquisition; distinct democratic governance.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_043', 'Jesuits (Order)', 'Catholic Religious Order', '1540 AD', 'Paris / Rome', 'The Shock Troops of the Counter-Reformation; known for special vow of obedience to the Pope, missionary adaptability, education, and suppression of Protestantism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_044', 'Cathars (Albigensians)', 'Gnostic / Dualist (Medieval)', 'c. 1100s AD', 'Languedoc (Southern France)', 'A major medieval heresy flourishing in Catholic territories; dualists who rejected the material world (and Catholic sacraments) as evil; had a hierarchy of Perfects and Believers.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_045', 'Knights Templar', 'Military Order', '1119 AD', 'Jerusalem', 'Monastic warrior order protecting pilgrims; became early bankers of Europe; suppressed by Pope Clement V and King Philip IV of France on charges of heresy and sodomy.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_046', 'Jansenists', 'Catholic (Heretical Movement)', '1640 AD', 'France / Low Countries', 'A theological movement emphasizing original sin, human depravity, and irresistible grace (similar to Calvinism); condemned by Rome but deeply influential in French piety.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_047', 'Old Catholic Church (Union of Utrecht)', 'Independent Catholic', '1870 AD', 'Netherlands / Germany', 'Formed by Catholics who rejected the dogma of Papal Infallibility (Vatican I); valid orders but now distinct for liberal stances (women''s ordination, LGBT blessing).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_048', 'Polish National Catholic Church', 'Independent Catholic', '1897 AD', 'Pennsylvania (USA)', 'Schism by Polish immigrants in the US protesting Irish-dominated hierarchy and demanding ownership of parish property; retains valid sacraments but separated from Rome.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_049', 'Liberal Catholic Church', 'Esoteric / Independent', '1916 AD', 'United Kingdom', 'Syncretic movement blending Catholic liturgy and orders with Theosophy and Eastern metaphysics (reincarnation); founded by Theosophists who were consecrated bishops.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_050', 'Iglesia Filipina Independiente (Aglipayan)', 'Independent Catholic', '1902 AD', 'Philippines', 'National church formed during the Philippine Revolution against Spanish friar dominance; initially Unitarian-leaning, now largely Anglican in theology but Catholic in ritual.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_051', 'Brazilian Catholic Apostolic Church (ICAB)', 'Independent Catholic', '1945 AD', 'Brazil', 'Founded by a generic Roman Catholic Bishop (Duarte Costa) excommunicated for criticizing the regime; known for lax canon law (divorce/remarriage) and mass ordinations of bishops.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_052', 'SSPX (Society of St. Pius X)', 'Traditionalist Catholic', '1970 AD', 'Switzerland', 'A priestly fraternity in irregular status; resists Vatican II reforms (ecumenism, religious liberty) and the New Mass; uses only the 1962 Missal; relations with Rome remain tense.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_053', 'Sedevacantists', 'Radical Traditionalist', 'c. 1970s AD', 'Global', 'A diffuse movement holding that the Papal See has been vacant (sede vacante) since the death of Pius XII (1958) because subsequent Popes espoused heresy (Modernism).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_054', 'Palmarian Catholic Church', 'Schismatic Sect', '1978 AD', 'El Palmar de Troya (Spain)', 'A cultic schism founded by a visionary who claimed to be crowned Pope by Christ directly; claimed the Holy See moved to Spain; has its own restrictive bible and canon of saints.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_055', 'Chinese Patriotic Catholic Association', 'State-Sanctioned Catholic', '1957 AD', 'Beijing (China)', 'The government-approved body for Catholics in China; historically ordained bishops without papal mandate; technically in a complex process of reconciliation with Rome since 2018.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_056', 'Catholic Charismatic Renewal (Movement)', 'Ecclesial Movement', '1967 AD', 'USA (Duquesne Univ.)', 'A movement within the Catholic Church emphasizing baptism in the Holy Spirit, tongues, and prophecy, similar to Pentecostalism but remaining doctrinally Catholic.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_057', 'Opus Dei (Prelature)', 'Personal Prelature', '1928 AD', 'Spain', 'A unique structure (Personal Prelature) composed of laity and priests; focuses on sanctification of work and strict orthodox discipline; influential in business and politics.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_058', 'Neocatechumenal Way', 'Ecclesial Movement', '1964 AD', 'Madrid (Spain)', 'A catechumenate for baptized adults focused on small communities and liturgical renewal; distinct for its Saturday night extended Eucharist and tight-knit community structure.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_059', 'Army of Mary (Community of the Lady of All Nations)', 'Schismatic / Heretical', '1971 AD', 'Quebec (Canada)', 'A mystical movement condemned by Rome; teaches that its founder is the reincarnation of the Virgin Mary and that the Trinity has been expanded to a Quaternity.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_060', 'Liberation Theology (Movement)', 'Catholic / Ecumenical (Movement)', 'c. 1960s AD', 'Latin America', 'A theological school interpreting the Gospel through the preferential option for the poor; emphasizes social-political liberation from unjust economic or social conditions.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_061', 'Folk Catholicism Movements', 'Catholic (Syncretic)', 'c. 1500s AD', 'Global South', 'The practice of ethnic/local traditions (e.g., Day of the Dead, Santería overlaps) under a Catholic veneer; often includes the veneration of folk saints not recognized by Rome.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_062', 'Assyrian Church of the East', 'Church of the East', '431 AD', 'Mesopotamia (Persian Empire)', 'The Nestorian church that rejected the Council of Ephesus; historically centered in Persia/Asia; distinct East Syriac Rite and Two Persons Christology (Dyophysite).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_063', 'Armenian Apostolic Church', 'Oriental Orthodox', '301 AD', 'Armenia', 'The world''s oldest national church; uses the Armenian Rite; rejected the Council of Chalcedon (Miaphysite theology); distinct for its badarak liturgy and animal sacrifice (matagh) tradition.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_064', 'Coptic Orthodox Church', 'Oriental Orthodox', '451 AD', 'Egypt (Alexandria)', 'The principal Christian body in Egypt; rejected Chalcedon to maintain that Christ has one incarnate nature of God the Word; uses the Coptic Rite and led by the Pope of Alexandria.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_065', 'Syriac Orthodox Church', 'Oriental Orthodox', '451 AD', 'Antioch / Syria', 'The Jacobite church; maintains West Syriac Rite and Miaphysite theology; historically used Syriac (Aramaic) as the liturgical language; spiritual center in the Tur Abdin region.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_066', 'Ethiopian Orthodox Tewahedo', 'Oriental Orthodox', 'c. 330 AD', 'Aksum (Ethiopia)', 'The largest Oriental Orthodox church; retains heavy Jewish influences (circumcision, pork prohibition, Saturday Sabbath); possesses the largest biblical canon (81 books) including Enoch.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_067', 'Malankara Orthodox Syrian Church', 'Oriental Orthodox', '52 AD / 1653 AD', 'Kerala (India)', 'The Indian Orthodox Church of the St. Thomas Christians; declared independence from Portuguese Catholic imposition in 1653 (Coonan Cross Oath); West Syriac Rite.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_068', 'Eastern Orthodox Church', 'Eastern Orthodox', '1054 AD', 'Byzantine Empire', 'The communion of autocephalous churches (Greek, Russian, Serbian, etc.) accepting 7 Ecumenical Councils; defined by Byzantine Rite, hesitation theology, and icons; split from Rome in 1054.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_069', 'Russian Old Believers (Raskol)', 'Schismatic Orthodox', '1666 AD', 'Russia', 'Separatists who rejected Patriarch Nikon''s liturgical reforms (e.g., three-finger sign of the cross); maintained pre-17th-century Russian rites; heavily persecuted historically.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_070', 'Lipovan Orthodox', 'Schismatic Orthodox', 'c. 1700s AD', 'Romania / Ukraine', 'A specific branch of Old Believers (Priested) who fled Russia to the Danube Delta; they maintain strict Old Rite traditions and distinct Slavic ethno-religious identity.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_071', 'True Orthodox (Old Calendarists)', 'Schismatic Orthodox', '1924 AD', 'Greece / Romania', 'Various groups that separated from mainstream Eastern Orthodoxy after the adoption of the Revised Julian Calendar; they view the mainstream church as fallen into the heresy of Ecumenism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_072', 'Celtic Christianity (Historic)', 'Insular Christianity', 'c. 400 AD', 'Ireland / Britain', 'The monastic-centered church of the British Isles; distinct calculation of Easter, tonsure, and penitential systems; eventually absorbed by the Roman Rite after the Synod of Whitby (664).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_073', 'Paulicians', 'Dualist / Iconoclast', 'c. 650 AD', 'Armenia / Anatolia', 'A dualist, adoptionist sect; rejected the Old Testament, sacraments, and hierarchy; highly militarized and fiercely iconoclastic; influenced later Balkan heresies.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_074', 'Bogomils', 'Gnostic / Dualist', 'c. 950 AD', 'Bulgaria / Macedonia', 'A neo-Gnostic peasant movement; taught that the material world was created by Satan; rejected the church hierarchy, baptism, and the cross; influenced the Western Cathars.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_075', 'Iconoclast Church', 'Byzantine State Church', '726 AD', 'Constantinople', 'The official state church during the Iconoclast periods; condemned the veneration of images as idolatry and persecuted Iconodules; theology emphasized the Eucharist as the only true image.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_076', 'Doukhobors', 'Spiritual Christian', 'c. 1700s AD', 'Russia', 'Spirit Wrestlers; a radical pacifist Russian sect rejecting liturgy, icons, scripture, and priesthood; believe God resides in the soul of the faithful; historically migrated to Canada.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_077', 'Molokans', 'Spiritual Christian', 'c. 1550s AD', 'Russia', 'Milk Drinkers (drank milk on fast days); rejected the institutional church, icons, and state authority; strictly biblical but interpret scripture spiritually/allegorically.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_078', 'Subbotniks', 'Judaizing Christian', 'c. 1700s AD', 'Russia', 'Russian peasants who adopted Old Testament practices (Saturday Sabbath, circumcision, dietary laws); some fully converted to Judaism, others remained Karaite/Christian hybrids.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_079', 'Renovationist Church (Living Church)', 'Schismatic Orthodox', '1922 AD', 'USSR', 'A Soviet-backed modernist schism from the Russian Orthodox Church; attempted to reconcile Christianity with Communism, allowed married bishops, and removed monarchist symbols.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_080', 'Western Rite Orthodox Communities', 'Eastern Orthodox (Rite)', '19th Century', 'West / USA', 'Communities within canonical Eastern/Oriental Orthodox churches that use restored Western (Gregorian/Tikhon) liturgies rather than the Byzantine Rite; theologically Orthodox but culturally Western.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_081', 'Waldensians', 'Proto-Protestant', 'c. 1173 AD', 'Lyon (France)', 'The oldest surviving proto-Protestant group; began as a lay preaching movement emphasizing poverty and memorization of vernacular scripture; rejected indulgences, purgatory, and oaths; later merged with the Reformed tradition.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_082', 'Lollards', 'Proto-Protestant', 'c. 1380 AD', 'Oxford (England)', 'Followers of Wycliffe who anticipated the English Reformation; advocated for a vernacular English Bible, rejected transubstantiation (remnance), and critiqued clerical wealth and the papacy as Antichrist.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_083', 'Petrobrusians (Henricians)', 'Radical Reformist', 'c. 1110 AD', 'Southern France', 'A radical anti-clerical movement; rejected infant baptism, the construction of church buildings (faith is in the person, not the stone), the veneration of crosses (which they burned), and prayers for the dead.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_084', 'Arnoldists', 'Political/Ecclesial Reform', 'c. 1140 AD', 'Rome / Brescia', 'Advocated for strict apostolic poverty and the surrender of the Church''s temporal power/property to the state; briefly established a Roman commune defying the Pope; precursors to separation of church and state.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_085', 'Utraquists (Calixtines)', 'Hussite', 'c. 1414 AD', 'Prague (Bohemia)', 'The moderate wing of the Hussite movement; demanded communion in both kinds (bread and cup) for the laity (the chalice became their symbol); maintained traditional liturgy but rejected total papal control.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_086', 'Taborites', 'Hussite (Radical)', '1420 AD', 'Tábor (Bohemia)', 'The militant, apocalyptic wing of the Hussites; rejected everything not explicitly found in Scripture (icons, purgatory, saints, fasts); established a communal society awaiting the return of Christ; crushed at the Battle of Lipany.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_087', 'Unitas Fratrum (Historic Hussites)', 'Hussite / Moravian', '1457 AD', 'Kunvald (Bohemia)', 'A pacifist separation from the Utraquists; emphasized the Sermon on the Mount, non-violence, and simple living; the direct ancestors of the modern Moravian Church (Herrnhuters).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_088', 'Picards (Neo-Adamites)', 'Radical Sectarian', 'c. 1418 AD', 'Bohemia / Flanders', 'A fringe group expelled by Taborites; attempted to return to an Edenic state of innocence, often practicing nudity and rejecting marriage/social norms; eventually annihilated by Ziska.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_089', 'Apostolic Brethren (Apostolics)', 'Radical Poverty', 'c. 1260 AD', 'Parma (Italy)', 'Rejected the institutional church''s wealth; roamed as itinerant preachers mimicking the apostles; eventually radicalized into an armed insurgency under Dolcino, predicting the destruction of the Whore of Babylon (the Church).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_090', 'Brethren of the Common Life', 'Devotio Moderna', 'c. 1380 AD', 'Deventer (Netherlands)', 'A pietist community of laypeople living in common without vows; emphasized inner spirituality, education, and copying scriptures; deeply influenced Luther and Erasmus (the Reform before the Reformation).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_091', 'Friends of God (Gottesfreunde)', 'Mystical Reform', 'c. 1340 AD', 'Rhineland (Germany)', 'A loose network of mystics (lay and clergy) seeking direct union with God amidst the Babylonian Captivity of the Papacy; prioritized inner experience over external sacraments; produced the Theologia Germanica.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_092', 'Strigolniki', 'Eastern Proto-Protestant', 'c. 1370 AD', 'Novgorod (Russia)', 'The Shorn Ones; early Russian dissenters who rejected the hierarchy due to simony (selling offices); rejected confession to priests, claiming only God forgives.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_093', 'Judaizers (Zhidovstvuyushchiye)', 'Eastern Proto-Protestant', 'c. 1470 AD', 'Novgorod / Moscow', 'An enigmatic group in Russia that denied the Trinity and divinity of Christ, rejected icons/monasticism, and adhered to Old Testament laws; historically termed Judaizers but functionally early Unitarian/Iconoclasts.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_094', 'Free Spirit (Brethren of the Free Spirit)', 'Antinomian / Mystical', 'c. 1200s AD', 'Northern Europe', 'A diffuse heresy teaching that the perfected soul is one with God and thus above moral law and church sacraments; while more Gnostic, their anti-clericalism and rejection of church authority parallels Protestant radicalism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_095', 'Savonarolans (Piagnoni)', 'Moral Reformist', 'c. 1490 AD', 'Florence (Italy)', 'The Weepers; followers of the friar Savonarola who established a theocratic republic in Florence; burned vanities (art/cosmetics); though theologically Catholic, their denunciation of papal corruption paved the way for the Reformation.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_096', 'Lutheran State Churches (Historic)', 'Lutheran', '1517 AD', 'Wittenberg (Germany)', 'The original Protestant tradition; emphasizes Sola Fide, the Real Presence (Sacramental Union), and the distinction between Law and Gospel; historically organized as state churches in Germany and Scandinavia.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_097', 'Gnesio-Lutherans', 'Lutheran', 'c. 1548 AD', 'Jena / Magdeburg', 'Genuine Lutherans; the strict orthodoxy faction that opposed compromises with Catholics (Adiaphora) and Calvinists; insisted on the total depravity of man and the Real Presence; solidified the Formula of Concord.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_098', 'Philippists', 'Lutheran', 'c. 1555 AD', 'Germany', 'Followers of Melanchthon; sought reconciliation with Calvinists on the Eucharist (Crypto-Calvinism) and emphasized human will in conversion; opposed by Gnesio-Lutherans.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_099', 'Pietism', 'Lutheran (Movement)', '1675 AD', 'Frankfurt (Germany)', 'A renewal movement within Lutheranism reacting against dead orthodoxy; emphasized personal conversion (Bußkampf), small group Bible study (collegia pietatis), and social activism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_100', 'Laestadianism (Apostolic Lutheranism)', 'Lutheran (Pietist)', '1844 AD', 'Lapland (Sweden/Finland)', 'A revivalist movement within Nordic Lutheranism; emphasizes the power of the keys (lay confession and absolution), exclusivity, and strict moral codes (rejection of contraception, alcohol).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_101', 'Old Lutherans', 'Lutheran (Confessional)', '1830 AD', 'Germany / USA', 'Groups that seceded from the state churches to reject the Prussian Union; insisted on strict adherence to the Book of Concord and distinct Lutheran liturgy; ancestors of the Missouri Synod (LCMS).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_102', 'Lutheran Church–Missouri Synod (LCMS)', 'Lutheran (Confessional)', '1847 AD', 'Chicago / St. Louis (USA)', 'The primary Confessional alternative to the ELCA; strictly adheres to the Book of Concord and Biblical inerrancy; practices closed communion and rejects women''s ordination and ecumenical syncretism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_103', 'Wisconsin Evangelical Lutheran Synod (WELS)', 'Lutheran (Confessional)', '1850 AD', 'Milwaukee (USA)', 'More conservative than the LCMS; breaks fellowship even with other conservatives over slight doctrinal disagreements (the concept of Fellowship); prohibits women from voting in church assemblies.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_104', 'Confessing Church (Bekennende Kirche)', 'Lutheran / Reformed', '1934 AD', 'Nazi Germany', 'A movement resisting the Nazi takeover of the German church (German Christians); issued the Barmen Declaration, asserting the church''s allegiance to Christ alone, not the Führer.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_105', 'Evangelical Lutheran Church in America (ELCA)', 'Lutheran (Mainline)', '1988 AD', 'USA', 'The primary Liberal/Mainline Lutheran body in North America; formed by merging three predecessor bodies; broadly ecumenical, ordains women and LGBTQ+ clergy, and is in full communion with the Episcopal Church and Reformed bodies.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_106', 'Reformed State Churches (Continental)', 'Reformed', '1536 AD', 'Geneva / Strasbourg', 'The major branch of the Reformation systematized by Calvin; emphasizes God''s sovereignty, election (predestination), and covenant theology; distinct from Presbyterianism by polity (Consistories vs. Presbyteries).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_107', 'Church of Scotland', 'Reformed', '1560 AD', 'Scotland', 'The British expression of Reformed theology; distinct for its system of governance by elders (presbyters) and synods rather than bishops; historically adhered to the Westminster Confession of Faith.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_108', 'Huguenots (Historic)', 'Reformed', 'c. 1550 AD', 'France', 'The French Reformed Church; historically a Church under the Cross defined by persecution (St. Bartholomew''s Day Massacre) and military resistance; strict Calvinist theology.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_109', 'Remonstrants (Arminians)', 'Reformed (Dissenting)', '1610 AD', 'Netherlands', 'A break from strict Calvinism; rejected unconditional election and limited atonement in favor of prevenient grace and free will; condemned at the Synod of Dort but highly influential on Methodism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_110', 'Hungarian Reformed Church', 'Reformed', '1567 AD', 'Debrecen (Hungary)', 'The Calvinist Rome of Eastern Europe; distinct for surviving under Ottoman rule and retaining a bishop-like superintendency despite being Reformed; deeply tied to Magyar national identity.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_111', 'Free Church of Scotland', 'Reformed (Presbyterian)', '1843 AD', 'Scotland', 'Formed by the Disruption of 1843; walked out of the established Church of Scotland over the issue of state interference in the calling of ministers (Patronage); distinctive for unaccompanied psalmody.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_112', 'Netherlands Reformed Congregations', 'Reformed (Hyper-Calvinist)', '1907 AD', 'Netherlands', 'Gerformeerde Gemeenten; a strict, experiential Calvinist federation; emphasizes the necessity of a specific conversion experience and maintains isolation from secular culture.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_113', 'Presbyterian Church (USA)', 'Reformed (Mainline)', '1983 AD', 'USA', 'The Mainline Presbyterian standard; formed by the reunion of Northern and Southern branches; historically theologically broad (Big Tent), socially progressive, and politically active on the left.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_114', 'Presbyterian Church in America (PCA)', 'Reformed (Confessional)', '1973 AD', 'Birmingham (USA)', 'The largest Confessional Presbyterian body; split from the mainline Southern church to protest theological liberalism; emphasizes Old School Calvinism, male-only leadership, and evangelical piety.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_115', 'Bible Presbyterian Church', 'Reformed (Fundamentalist)', '1937 AD', 'USA', 'A break from the OPC led by Carl McIntire; distinct for combining Reformed theology with Dispensationalism (pro-Israel), teetotalism (no alcohol), and militant anti-communism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_116', 'Puritans (Historic)', 'Anglican / Reformed', 'c. 1560 AD', 'England', 'A movement within the Church of England seeking to purify it of Roman catholic rituals (vestments, kneeling); emphasized preaching, Sabbatarianism, and experiential grace; ancestors of Congregationalists.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_117', 'Congregationalists (Independents)', 'Reformed', '1582 AD', 'England / Netherlands', 'Reformed theology with a distinct polity: every local congregation is autonomous and accountable directly to Christ (no bishops or presbyteries); authors of the Savoy Declaration.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_118', 'Unitarianism (Historic)', 'Nontrinitarian (Post-Puritan)', 'c. 1774 AD', 'London / Boston', 'Evolved directly out of English Presbyterians and New England Congregationalists (Puritans) who rejected the Trinity using Reason in Religion; historically Christian, now largely pluralist.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_119', 'Universalist Church (Historic)', 'Universalist', '1793 AD', 'USA', 'Arose from Calvinist/Baptist backgrounds rejecting Limited Atonement; taught Universal Salvation (all will be saved); merged with Unitarians in 1961 to form the UUA.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_120', 'Unitarian Universalism (UUA)', 'Pluralist (Post-Christian)', '1961 AD', 'USA', 'A merger of two historic Christian denominations (Unitarians and Universalists) that has evolved into a non-creedal, pluralist religion drawing from all world faiths.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_121', 'Church of England (Anglicanism)', 'Anglican', '1534 AD', 'England', 'The Via Media (Middle Way) between Geneva and Rome; distinct for retaining the episcopacy and liturgical Book of Common Prayer while adopting Reformed soteriology; the mother church of the Anglican Communion.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_122', 'Non-Jurors', 'Anglican (Schism)', '1688 AD', 'England / Scotland', 'High Church Anglicans who refused to swear allegiance to William III after the ousting of James II; maintained a distinct, more Catholic liturgy and theology detached from the state.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_123', 'Scottish Episcopal Church', 'Anglican', '1689 AD', 'Scotland', 'The Anglican province in Scotland; suppressed for Jacobite sympathies; distinct for having a liturgy closer to Eastern Orthodoxy (the Epiclesis) than the English 1662 Book of Common Prayer; consecrated the first US bishop.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_124', 'Oxford Movement (Tractarians)', 'Anglican (Movement)', '1833 AD', 'Oxford (England)', 'The rise of Anglo-Catholicism; argued the Church of England is a branch of the Church Catholic; reintroduced rituals, monasticism, and high sacramental theology to Anglicanism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_125', 'Reformed Episcopal Church', 'Anglican (Schism)', '1873 AD', 'New York (USA)', 'A Low Church schism from the US Episcopal Church; formed to protest the rise of ritualism (Anglo-Catholicism); emphasizes the Protestant/Evangelical character of the 39 Articles.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_126', 'Continuing Anglicanism', 'Anglican (Traditionalist)', '1977 AD', 'St. Louis (USA)', 'Various churches that separated from the Anglican Communion to reject the ordination of women and liturgical revisions; they affirm the Affirmation of St. Louis.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_127', 'GAFCON / Global Anglicans (Fellowship)', 'Anglican (Confessing)', '2008 AD', 'Jerusalem / Global South', 'A global fellowship of Confessing Anglicans who reject the authority of the Archbishop of Canterbury; affirms the Jerusalem Declaration and strict biblical moral codes.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_128', 'The Episcopal Church (TEC)', 'Anglican (Mainline)', '1789 AD', 'USA', 'The primary Liberal Mainline Anglican body in the US; known for its progressive stance on social issues, distinctive Broad Church liturgy, and historic political influence.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_129', 'Mar Thoma Syrian Church', 'Reformed / St. Thomas Christian', '1889 AD', 'Kerala (India)', 'A unique hybrid church; it is a St. Thomas Christian body that underwent a Reformed awakening via Anglican influence, keeping the West Syriac Rite but adopting Protestant theology.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_130', 'Swiss Brethren (Historic)', 'Anabaptist', '1525 AD', 'Zurich (Switzerland)', 'The original Anabaptist movement; rejected infant baptism (re-baptizers) and swore absolute pacifism (the Schleitheim Confession); persecuted by both Zwingli and Catholics.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_131', 'Mennonites', 'Anabaptist', '1536 AD', 'Friesland (Netherlands)', 'Followers of Menno Simons who rallied the peaceful Anabaptists after the Münster disaster; defined by pacifism, separation from the world, and believer''s baptism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_132', 'Hutterites', 'Anabaptist (Communal)', '1528 AD', 'Tyrol / Moravia', 'Distinct for practicing community of goods (absolute communal ownership of property) based on Acts 2; live in secluded agricultural colonies (Bruderhofs).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_133', 'Münsterites', 'Anabaptist (Radical)', '1534 AD', 'Münster (Germany)', 'A violent, apocalyptic sect that seized the city of Münster to establish the New Jerusalem; practiced polygamy and enforced communism before being massacred by armies.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_134', 'Amish (Old Order)', 'Anabaptist', '1693 AD', 'Switzerland / Alsace', 'A schism from the Swiss Mennonites led by Jakob Ammann; demanded stricter church discipline (shunning/Meidung) and foot washing; known today for rejecting modern technology (cars, grid electricity).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_135', 'Mennonite Brethren', 'Anabaptist (Pietist)', '1860 AD', 'Ukraine (Russia)', 'Formed among German colonies in Russia; influenced by Lutheran Pietism; emphasizes a specific crisis conversion experience and immersion baptism (unlike the pouring of traditional Mennonites).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_136', 'Brethren in Christ (River Brethren)', 'Anabaptist / Pietist', 'c. 1770 AD', 'Pennsylvania (USA)', 'A synthesis of Anabaptist theology and Wesleyan holiness/pietism; historically practiced trine immersion; the ecclesiastical home of the Eisenhower family.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_137', 'Schwarzenau Brethren (Dunkers)', 'Anabaptist / Pietist', '1708 AD', 'Schwarzenau (Germany)', 'German Baptists; combined Radical Pietism with Anabaptist ecclesiology; distinct for Trine Immersion (dunking three times forward) and the Love Feast (communion + meal + foot washing).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_138', 'Bruderhof Communities', 'Anabaptist (Restorationist)', '1920 AD', 'Germany', 'A modern restoration of Hutterite-style communal living; founded by a Protestant intellectual; historically persecuted by Nazis, now located globally.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_139', 'General Baptists (17th Century)', 'Baptist (Arminian)', '1609 AD', 'Amsterdam / London', 'The first English Baptists; influenced by Mennonites; believed in unlimited atonement (Christ died for all) and that believers can fall from grace (Arminian theology).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_140', 'Reformed Baptists (17th Century)', 'Baptist (Calvinist)', '1638 AD', 'London', 'The main trunk of modern Baptist theology; adhered to Calvinist soteriology (Limited Atonement) and emerged from independent Puritan congregations; authors of the 1689 London Baptist Confession.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_141', 'Seventh Day Baptists', 'Baptist (Sabbatarian)', '1650 AD', 'London', 'Baptists who observe the Saturday Sabbath; emerged during the English Puritan ferment; heavily influenced the later formation of Seventh-day Adventism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_142', 'American Baptist Churches USA (Mainline)', 'Baptist (Mainline)', '1814 AD', 'Philadelphia (USA)', 'The Northern Baptist tradition; originally the national mission board; generally more ecumenical, allowing for women in ministry and open communion; the theological home of Martin Luther King Jr.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_143', 'Primitive Baptists', 'Baptist (Hyper-Calvinist)', 'c. 1830 AD', 'Southern USA', 'A strictly anti-missionary group; rejected Sunday Schools, mission boards, and musical instruments as non-biblical innovations; adhere to strong predestination (Hyper-Calvinism).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_144', 'Southern Baptist Convention (SBC)', 'Baptist (Evangelical)', '1845 AD', 'Augusta, GA (USA)', 'Formed by a split from the Triennial Convention over the right of slaveholders to be missionaries; now the world''s largest Baptist body; conservative, non-creedal, and autonomous.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_145', 'Landmark Baptists', 'Baptist (Successionist)', '1851 AD', 'Tennessee (USA)', 'A movement believing Baptists are the only true church, existing in an unbroken chain since John the Baptist (Trail of Blood); practice Closed Communion (members only) and reject alien immersion.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_146', 'Free Will Baptists', 'Baptist (Arminian)', '1727 AD', 'North Carolina (USA)', 'The survival of the General Baptist theology in America; emphasizes that salvation is available to all and can be forfeited (apostasy); practices foot washing as an ordinance.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_147', 'National Baptist Convention', 'Baptist (Black Church)', '1895 AD', 'Atlanta (USA)', 'The largest historic African American denomination; formed after the Civil War to allow black congregations independence from white control; combines Baptist polity with social justice advocacy.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_148', 'Independent Fundamental Baptists (IFB)', 'Baptist (Fundamentalist)', 'c. 1920s AD', 'USA / Global', 'A loose network of strictly separatist churches; reject all denominational hierarchies; typically KJV-Only, anti-ecumenical, and highly rigorous on lifestyle standards.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_149', 'Naga Baptist Church', 'Baptist (Ethnic)', '1872 AD', 'Nagaland (India)', 'A massive Baptist movement among the Naga people (former headhunters); the result of American missionary work; distinct for its near-total integration into Naga cultural and national identity (Nagaland is The only Baptist state in the world).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_150', 'Spiritual Baptists (Shouters)', 'Syncretic Baptist', 'c. 1900s AD', 'Trinidad / St. Vincent', 'An Afro-Caribbean faith blending Baptist structure with West African spirituality; distinct for mourning rituals, bell-ringing, and ecstatic possession by the Holy Spirit.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_151', 'Westboro Baptist Church', 'Baptist (Hate Group)', '1955 AD', 'Kansas (USA)', 'A tiny, hyper-Calvinist cult (God Hates Fags); distinct for picketing funerals and believing the church consists only of their specific congregation; widely condemned by all other Baptist groups.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_152', 'Methodist Church of Great Britain', 'Methodist', '1739 AD', 'London / Bristol', 'The Mother Church of Methodism; distinct from American Methodism (no bishops, ruled by Conference); historically emphasized class meetings and field preaching.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_153', 'United Methodist Church (UMC)', 'Methodist (Mainline)', '1968 AD', 'Dallas (USA)', 'The largest Methodist body (merger of Methodist Episcopal and EUB); a big tent theology ranging from evangelical to liberal; currently undergoing schism over sexuality.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_154', 'African Methodist Episcopal Church (AME)', 'Methodist (Black Church)', '1816 AD', 'Philadelphia (USA)', 'The first independent black denomination in the US; formed to escape racial discrimination in white Methodist churches; retains strict Methodist polity and doctrine.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_155', 'Free Methodist Church', 'Methodist (Holiness)', '1860 AD', 'New York (USA)', 'A split from mainstream Methodism; opposed pew rents (hence Free), slavery, and secret societies; emphasizes the entire sanctification of the believer.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_156', 'Calvinistic Methodists (Presbyterian Church of Wales)', 'Methodist / Reformed', '1811 AD', 'Wales', 'A unique hybrid; Methodist in revivalist fervor but Calvinist in theology (following Whitefield rather than Wesley); the driving force of the Welsh Revivals.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_157', 'The Salvation Army', 'Methodist (Holiness)', '1865 AD', 'London', 'A Holiness movement with a quasi-military structure (Generals, Soldiers); distinct for rejecting all outward sacraments (baptism/communion) as unnecessary; famous for social service.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_158', 'Church of the Nazarene', 'Holiness (Wesleyan)', '1908 AD', 'Texas (USA)', 'The largest Holiness denomination; formed to preserve the doctrine of Christian Perfection (Second Work of Grace) which they felt Methodism was abandoning.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_159', 'Global Methodist Church', 'Methodist (Conservative)', '2022 AD', 'USA / Global', 'The conservative breakaway from the UMC; formed to maintain traditional teachings on marriage and sexuality; officially adheres to historic Wesleyan orthodoxy.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_160', 'Church of God (Cleveland)', 'Pentecostal (Holiness)', '1886 AD', 'Tennessee (USA)', 'One of the oldest Pentecostal bodies; has Holiness roots (requires sanctification before Spirit baptism); distinct for centralized government and foot washing practice.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_161', 'Church of God in Christ (COGIC)', 'Pentecostal (Black Church)', '1897 AD', 'Mississippi (USA)', 'The largest African American Pentecostal body; distinct for its Holy Convocation, liturgical vestments (rare in Pentecostalism), and massive musical influence on American culture.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_162', 'Pentecostal Holiness Church (IPHC)', 'Pentecostal (Holiness)', '1898 AD', 'North Carolina (USA)', 'A strict Three Stage theology: 1. Justification, 2. Entire Sanctification (Holiness), 3. Baptism in the Spirit (Tongues); fused Southern Holiness with Azusa spirituality.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_163', 'Apostolic Faith Church', 'Pentecostal (Classical)', '1906 AD', 'Los Angeles (USA)', 'The Jerusalem of Pentecostalism; the direct result of the Azusa Street Revival; prioritized the baptism of the Holy Spirit evidenced by speaking in tongues.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_164', 'International Church of the Foursquare Gospel', 'Pentecostal (Classical)', '1923 AD', 'Los Angeles (USA)', 'Founded by the celebrity evangelist Aimee Semple McPherson; teaches Jesus as Savior, Baptizer, Healer, and Coming King; pioneered radio evangelism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_165', 'United Pentecostal Church International (UPCI)', 'Pentecostal (Oneness)', '1945 AD', 'Missouri (USA)', 'The largest Oneness (Nontrinitarian) body; baptizes in the name of Jesus Only (Acts 2:38); teaches that God is one person (Jesus) and rejects the Trinity as pagan.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_166', 'Pentecostal Assemblies of the World (PAW)', 'Pentecostal (Oneness)', '1906 AD', 'Los Angeles / Indianapolis', 'The oldest Oneness organization; historically interracial (though now predominantly Black); holds similar theology to UPCI but with different polity and history.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_167', 'Assemblies of God (World Fellowship)', 'Pentecostal (Finished Work)', '1914 AD', 'Arkansas (USA)', 'The world''s largest Pentecostal denomination; teaches the Finished Work (sanctification is progressive, not a crisis event); formed to provide structure to the revival.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_168', 'The Apostolic Church (UK/Wales)', 'Pentecostal (Restorationist)', '1916 AD', 'Wales (UK)', 'Emerged from the Welsh Revival; distinct for its emphasis on the restoration of the office of Apostle and Prophet as governing authorities in the church today.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_169', 'Vineyard Movement', 'Neo-Pentecostal (Third Wave)', '1974 AD', 'California (USA)', 'Empowered Evangelicals; emphasizes signs and wonders (healing/prophecy) but rejects the hype and cultural baggage of classical Pentecostalism; casual worship style.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_170', 'Calvary Chapel', 'Neo-Pentecostal / Evangelical', '1965 AD', 'California (USA)', 'The Jesus People movement church; combines Pentecostal openness to gifts with rigid verse-by-verse Bible exposition; anti-denominational Moses Model leadership.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_171', 'Universal Church of the Kingdom of God (IURD)', 'Neo-Pentecostal (Prosperity)', '1977 AD', 'Rio de Janeiro (Brazil)', 'A massive, controversial Brazilian empire; emphasizes Spiritual Warfare (exorcisms), Prosperity Theology, and tithing; owns major media networks (RecordTV).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_172', 'Redeemed Christian Church of God (RCCG)', 'Pentecostal (African)', '1952 AD', 'Lagos (Nigeria)', 'One of the fastest-growing churches globally; known for the Holy Ghost Service (millions attending); strict moral conservatism combined with aggressive expansion.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_173', 'Winners'' Chapel (Living Faith Church)', 'Pentecostal (Word of Faith)', '1983 AD', 'Nigeria', 'A major proponent of the Prosperity Gospel (Health and Wealth); built the Faith Tabernacle (50,000 seats); focus on faith as a spiritual force to conquer poverty.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_174', 'Word of Life (Livets Ord)', 'Neo-Pentecostal (Word of Faith)', '1983 AD', 'Uppsala (Sweden)', 'The primary European expression of American Word of Faith theology; highly influential in the former Soviet Union; emphasizes positive confession and success.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_175', 'Hillsong Church', 'Neo-Pentecostal', '1983 AD', 'Sydney (Australia)', 'Originally Hills Christian Life Centre; revolutionized global worship music (CCM); characterized by concert-like services, sleek branding, and a come as you are aesthetic.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_176', 'Zion Christian Church (ZCC)', 'African Independent (AIC)', '1924 AD', 'Moria (South Africa)', 'The largest church in Southern Africa; a syncretic blend of Pentecostalism and African tradition; members wear distinctive star badges and khaki uniforms; focus on healing and prophecy.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_177', 'Kimbanguist Church', 'African Independent (AIC)', '1921 AD', 'Congo (DRC)', 'Founded by the prophet Simon Kimbangu; originally anti-colonial; strictly puritanical (no alcohol/pork); trinitarian but highly focused on the person of the founder as a special envoy of the Spirit.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_178', 'Church of God with Signs Following', 'Pentecostal (Sign Handling)', 'c. 1910 AD', 'Appalachia (USA)', 'Small, isolated sect practicing Snake Handling and drinking poison based on a literal reading of Mark 16:17-18; no central headquarters, highly independent.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_179', 'Shakers (United Society of Believers)', 'Restorationist (Communal)', '1774 AD', 'Manchester (UK) / USA', 'A radical celibate, communal sect famous for ecstatic dance (shaking), simple furniture, and gender equality; believe Christ returned in the person of Mother Ann Lee.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_180', 'Churches of Christ (A Cappella)', 'Restorationist (Stone-Campbell)', '1906 AD', 'USA (Tennessee)', 'Emerged from the 19th-century Great Revival; distinct for rejecting instrumental music in worship and teaching that baptism by immersion is essential for salvation.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_181', 'International Churches of Christ (ICOC)', 'Restorationist (Stone-Campbell)', '1979 AD', 'Boston (USA)', 'Known as the Boston Movement; a schism from the Churches of Christ that emphasized aggressive discipling (one-on-one mentorship) and the belief that they were the only true church.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_182', 'Christian Church (Disciples of Christ)', 'Restorationist (Stone-Campbell)', '1832 AD', 'USA (Kentucky)', 'The liberal, mainline branch of the movement; practices weekly open communion and is heavily involved in ecumenical dialogue; congregational but has a denominational structure.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_183', 'Christian Churches and Churches of Christ (Independent)', 'Restorationist (Stone-Campbell)', '1927 AD', 'USA (Midwest)', 'The middle ground of the movement; distinct for using instrumental music (unlike CoC) but maintaining a conservative evangelical theology (unlike the Disciples).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_184', 'The Church of Jesus Christ of Latter-day Saints (LDS)', 'Restorationist (LDS)', '1830 AD', 'New York (USA)', 'The Mainstream Mormon church; teaches a restoration through Joseph Smith, possesses additional scripture (Book of Mormon), and focuses on temple ordinances and family history.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_185', 'Community of Christ', 'Restorationist (LDS)', '1860 AD', 'Illinois (USA)', 'Originally the Reorganized LDS (RLDS); led by descendants of Joseph Smith until 1996; emphasizes peace and social justice, and has moved closer to mainline Trinitarian Protestantism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_186', 'FLDS (Fundamentalist LDS)', 'Restorationist (LDS)', 'c. 1930s AD', 'Utah / Arizona (USA)', 'A radical breakaway that maintains the practice of Celestial Marriage (polygamy); live in isolated, high-control communities; rejected the LDS Church''s 1890 ban on polygamy.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_187', 'Seventh-day Adventist Church', 'Restorationist (Adventist)', '1863 AD', 'Michigan (USA)', 'Emerging from the Millerite movement; distinct for observing the Saturday Sabbath, a holistic health message (vegetarianism), and the prophetic authority of Ellen G. White.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_188', 'Advent Christian Church', 'Restorationist (Adventist)', '1860 AD', 'USA (New England)', 'A branch of Millerites that rejected Ellen G. White’s visions; teaches Conditional Immortality (the soul sleeps until resurrection) and focuses on the literal second coming of Christ.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_189', 'Church of God (Seventh Day)', 'Restorationist (Adventist)', '1863 AD', 'USA (Michigan)', 'Sabbatarian Adventists who rejected Ellen White; emphasize a strict biblical Unitarianism (historically) or subordinationism and the literal keeping of the Ten Commandments.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_190', 'Jehovah''s Witnesses', 'Restorationist (Nontrinitarian)', '1872 AD', 'Pennsylvania (USA)', 'Emerged from the Bible Student movement; nontrinitarian (believe Jesus is Michael the Archangel); reject blood transfusions and birthdays; governed by the Watch Tower Society.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_191', 'Christadelphians', 'Restorationist (Nontrinitarian)', '1844 AD', 'UK / USA', 'Brethren in Christ; hold a strict Unitarian theology, reject the personhood of the Devil, and believe in conditional immortality; strictly pacifist and do not participate in politics.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_192', 'Christian Science (First Church of Christ, Scientist)', 'Restorationist / Metaphysical', '1879 AD', 'Boston (USA)', 'Teaches that the material world is an illusion and that Divine Mind heals all sickness; distinct for its lack of traditional sacraments and focus on the textbook Science and Health.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_193', 'Unity Church (Unity School of Christianity)', 'Metaphysical / New Thought', '1889 AD', 'Missouri (USA)', 'A practical Christianity movement; interprets the Bible allegorically; emphasizes the Christ consciousness within every person and the power of positive thinking/affirmation.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_194', 'New Church (Swedenborgianism)', 'Nontrinitarian / Mystical', '1787 AD', 'London (UK)', 'Based on the writings of Emanuel Swedenborg; teaches a unique Correspondence theology where the Bible has internal spiritual meanings; views God as one person (Jesus Christ).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_195', 'Iglesia ni Cristo (Church of Christ)', 'Restorationist (Nontrinitarian)', '1914 AD', 'Philippines', 'A major global church founded in the Philippines; teaches that the Trinity is unbiblical and that Felix Manalo was the last messenger of God; characterized by strict discipline.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_196', 'Exclusive Brethren (Plymouth Brethren)', 'Restorationist (Separatist)', 'c. 1848 AD', 'UK / Ireland', 'The most separatist branch of the Plymouth Brethren; practice a rigid principle of separation from the world, avoiding social contact or eating with non-members.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_197', 'Open Brethren (Plymouth Brethren)', 'Restorationist (Separatist)', 'c. 1848 AD', 'UK / Ireland', 'Moderate branch of the Plymouth Brethren; emphasize the priesthood of all believers (no formal clergy) and weekly breaking of bread, but allow fellowship with other Christians.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_198', 'New Apostolic Church', 'Restorationist (Apostolic)', '1863 AD', 'Hamburg (Germany)', 'A schism from the Catholic Apostolic Church; teaches that the office of Apostle has been restored and is necessary for salvation and the sealing of the Holy Spirit.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_199', 'Christ Community Church (Zion City)', 'Restorationist (Healing)', '1896 AD', 'Chicago (USA)', 'Founded as a utopian theocracy in Zion, Illinois; emphasized divine healing and the imminent return of Christ; highly influential on African Pentecostalism (Zionist churches).');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_200', 'The Family International (Children of God)', 'Restorationist (Communal)', '1968 AD', 'California (USA)', 'Originally a radical Jesus People cult; known for communal living and unconventional evangelism methods; has undergone major restructuring and is now a decentralized network.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_201', 'Unification Church (Moonies)', 'Restorationist (Syncretic)', '1954 AD', 'Seoul (Korea)', 'Claims Sun Myung Moon is the True Parent finishing Jesus'' mission; distinct for mass weddings (Blessings) and a complex theology blending Christianity with Eastern philosophy.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_202', 'La Luz del Mundo', 'Restorationist / Alternative', '1926 AD', 'Guadalajara (Mexico)', 'Teaches that the primitive Christian church was restored through their specific Apostles; characterized by massive temple architecture and strict internal discipline.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_203', 'Shincheonji (Church of Jesus)', 'Alternative (NRM)', '1984 AD', 'Gwacheon (S. Korea)', 'A high-growth Korean movement; teaches that the Bible is written in secret metaphors and that their founder is the Promised Pastor who alone can interpret the Book of Revelation.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_204', 'World Mission Society Church of God', 'Alternative (NRM)', '1964 AD', 'Seoul (S. Korea)', 'Distinct for the belief in God the Mother (Zahng Gil-jah) alongside God the Father; observes the Passover and Saturday Sabbath; teaches that the founder was the second coming of Christ.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_205', 'Brotherhood of the Cross and Star', 'Alternative (Syncretic)', '1956 AD', 'Calabar (Nigeria)', 'Teaches that their founder is the Holy Spirit Incarnate and the King of Kings; practices vegetarianism, barefoot worship, and a unique form of communal living.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_206', 'Christian Identity', 'Alternative (Radical)', 'c. 1920s AD', 'USA', 'A white supremacist theology teaching that Anglo-Saxons are the true biblical Israelites and that non-whites and Jews are mud people or of Satanic origin; widely condemned.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_207', 'Black Hebrew Israelites', 'Alternative (Racial)', '1896 AD', 'Kansas / Chicago (USA)', 'Teaches that African Americans are the true physical descendants of the ancient Israelites; ranges from mainstream Christian-aligned groups to radical, anti-white fringe sects.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_208', 'Christian Spiritualist Church', 'Alternative (Spiritualist)', 'c. 1850s AD', 'UK / USA', 'Blends Christian liturgy and theology with the practice of mediumship; teaches that Jesus was the highest medium and that communication with the dead is a biblical spiritual gift.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_209', 'The Way International', 'Alternative (Biblical Unitarian)', '1942 AD', 'Ohio (USA)', 'A biblical research and teaching organization; denies the Trinity (Unitarian) and emphasizes Power for Abundant Living and the accuracy of the Aramaic New Testament.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_210', 'Emerging Church', 'Post-Protestant', 'c. 1990s AD', 'USA / UK', 'A deconstructionist movement that sought to adapt Christianity to postmodern culture; emphasized storytelling, social justice, and holy doubt over traditional dogma.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_211', 'Lectorium Rosicrucianum', 'Esoteric (Gnostic)', '1924 AD', 'Haarlem (Netherlands)', 'A Gnostic School that blends Christian mysticism with Rosicrucianism; teaches a path of Transfiguration to return the divine spark within humans to the original spiritual realm.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_212', 'Self-Realization Fellowship (Christian Yoga)', 'Syncretic / Esoteric', '1920 AD', 'India / USA', 'While primarily Hindu/Kriya Yoga, it teaches that Jesus and Krishna taught the same Original Christianity; interprets the Second Coming as the awakening of Christ-consciousness.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_213', 'Church of Almighty God', 'Alternative (Cult)', '1991 AD', 'China', 'Eastern Lightning; teaches Jesus has returned as a Chinese woman; highly secretive and aggressive.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_214', 'Local Churches (Living Stream Ministry)', 'Independent (Recovery)', '1922 AD', 'Fuzhou (China)', 'Based on the Recovery theology of Watchman Nee; rejects denominationalism, holding that there is only one church per city; emphasizes calling on the name of the Lord and God-man living.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_215', 'Cherubim and Seraphim (C&S)', 'African Independent (Aladura)', '1925 AD', 'Lagos (Nigeria)', 'One of the original Aladura (Praying) churches; emphasizes white garments, barefoot worship, and the use of psalms and prayer for spiritual protection and healing.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_216', 'Christ Apostolic Church (CAC)', 'African Independent (Aladura)', '1918 AD', 'Nigeria (Oyo)', 'The first major Aladura revival movement; distinct for its emphasis on prayer mountains (Ori Oke), use of prayer water, and strict reliance on divine healing without medicine.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_217', 'Three-Self Patriotic Movement (TSPM)', 'Protestant (State-Sanctioned)', '1954 AD', 'Beijing (China)', 'The government-approved umbrella for all Protestants in China; defined by the Three-Self principle (self-governance, self-support, self-propagation) to ensure independence from foreign influence.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_218', 'House Church Movement (China)', 'Independent (Underground)', '1949 AD', 'China', 'A decentralized network of unauthorized underground churches in China; characterized by extreme resilience, intense prayer, and a rejection of government-sanctioned oversight.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_219', 'African Orthodox Church', 'Independent Orthodox (Black Church)', '1921 AD', 'New York (USA)', 'Founded by a former Episcopalian priest associated with Marcus Garvey; intended to provide a racial and spiritual home for the African Diaspora; not in communion with canonical Eastern Orthodoxy.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_220', 'Believers Eastern Church', 'Independent / Eastern Liturgical', '2003 AD', 'Kerala (India)', 'Originally a non-denominational evangelical body (Gospel for Asia); it transitioned into an episcopal structure with Eastern vestments and liturgy while maintaining evangelical mission goals.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_221', 'Religious Society of Friends (Unprogrammed/Liberal)', 'Quaker', '1650 AD', 'England', 'The Silent Quakers; practice waiting worship without clergy or sacraments, emphasizing the Inner Light and social activism; includes the Hicksite tradition.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_222', 'Conservative Friends (Wilburites)', 'Quaker', '1845 AD', 'USA (New England)', 'A small but distinct group maintaining the Plain tradition; they hold to unprogrammed worship and traditional Quaker speech/dress, resisting both liberalism and evangelicalism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_223', 'Evangelical Friends Church International', 'Quaker', '1947 AD', 'USA', 'A branch of Quakerism that adopted programmed worship (pastors/music) and evangelical theology; emphasizes the authority of Scripture and missions over silent waiting.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_224', 'Christian and Missionary Alliance (C&MA)', 'Evangelical (Holiness)', '1887 AD', 'New York (USA)', 'Founded to focus on global missions; teaches the Fourfold Gospel (Jesus as Savior, Sanctifier, Healer, and Coming King); non-Pentecostal but emphasizes divine healing.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_225', 'Evangelical Free Church (EFCA)', 'Evangelical', '1884 AD', 'USA (Midwest)', 'Formed by Scandinavian immigrants; distinct for its no-creed-but-the-Bible stance and radical congregational autonomy; a central pillar of American Evangelicalism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_226', 'Evangelical Covenant Church (ECC)', 'Evangelical (Pietist)', '1885 AD', 'Chicago (USA)', 'Emerged from Swedish Lutheran Mission Friends; emphasizes the necessity of the new birth and a mixture of Lutheran heritage with free-church congregationalism.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_227', 'Independent Bible Churches', 'Evangelical (Fundamentalist)', 'c. 1920 AD', 'USA', 'Congregations that left mainline denominations during the Modernist-Fundamentalist controversy; typically adhere to Dispensationalism and strict Biblical inerrancy.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_228', 'Seeker-Sensitive Movement', 'Evangelical (Movement)', '1975 AD', 'Illinois (USA)', 'A church-growth strategy (Willow Creek/Saddleback) that adapts the church environment to be more accessible to non-believers, often removing traditional religious symbols.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_229', 'Progressive Christianity', 'Progressive / Post-Liberal', 'c. 1990s AD', 'USA / UK', 'A movement found within mainline churches (UCC, TEC) and independent circles; emphasizes social justice, environmentalism, and a non-literal/metaphorical interpretation of dogma.');
INSERT OR REPLACE INTO denominations (id, name, family, founded_year, region_origin, description) VALUES ('DENOM_230', 'Messianic Judaism', 'Messianic / Jewish Christian', 'c. 1960s AD', 'USA / Israel', 'A movement that combines Christian theology (Jesus as Messiah/God) with Jewish religious practice and identity; distinct from Hebrew Christians by its emphasis on keeping the Torah.');

