-- ==========================================
-- TABLE: answer_options
-- ==========================================
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_01_A01', 'GOD_01', 'One God existing as three distinct, co-equal persons', 'Trinitarianism', 'God is one being in three co-equal, co-eternal, and consubstantial persons: Father, Son, and Holy Spirit.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_01_A02', 'GOD_01', 'One God who plays three different roles or modes', 'Modalism', 'God is one person who has manifested in three different modes or roles: Father, Son, and Holy Spirit.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_01_A03', 'GOD_01', 'Two divine persons (Father & Son); the Spirit is power', 'Binitarianism', 'The Godhead consists of two co-eternal persons, the Father and the Son, while the Holy Spirit is God''s power or influence.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_01_A04', 'GOD_01', 'One supreme Father and a pre-existent created, subordinate Son', 'Arianism', 'God is one person (the Father), and Jesus is a created spiritual being (the Son) who is subordinate to Him.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_01_A05', 'GOD_01', 'Three separate divine beings perfectly united in purpose', 'Tritheism', 'The Godhead consists of three distinct and separate divine beings (personages) who are perfectly united in purpose.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_01_A06', 'GOD_01', 'Two opposing gods or forces (Good Spirit vs. Evil Matter)', 'Cosmic Dualism', 'There are two opposing divine principles or beings, one of spirit (good) and one of matter (evil).');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_01_A07', 'GOD_01', 'One God who adopted the human Jesus as His Son', 'Adoptionism', 'God is one person (the Father); Jesus was a human being adopted as God''s Son at his baptism or resurrection.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_01_A10', 'GOD_01', 'One God (Father); Jesus was a created human Messiah', 'Biblical Unitarianism', 'God is one person (the Father); Jesus is the unique human Son of God from conception, not a pre-existent being.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_01_A08', 'GOD_01', 'One God containing both male and female characteristics', 'Divine Androgyny', 'God is a single being possessing dual, complementary characteristics of masculinity and femininity.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_01_A09', 'GOD_01', 'One God; "Father, Son, Spirit" are metaphors, not persons', 'Symbolic Trinitarianism', 'The language of "Father, Son, and Spirit" is symbolic of God''s nature and activity, not a literal description of persons.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_04_A01', 'GOD_04', 'God determines every event; humans have no independent will', 'Theological Determinism', 'God''s decree is the sole cause of everything; human choices are fully determined by Him, leaving no independent human will.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_04_A02', 'GOD_04', 'God decrees the outcome but works through free human choices', 'Compatibilism', 'God sovereignly decides history''s outcome, but brings it about through the real, voluntary choices of human beings.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_04_A03', 'GOD_04', 'God secures outcomes by arranging circumstances', 'Molinism', 'God knows what free creatures would do in any situation, so He creates the specific scenario where they freely choose what He intends.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_04_A04', 'GOD_04', 'God foresees the future without controlling it', 'Simple Foreknowledge', 'God perfectly knows the future choices humans will make, and governs the world by responding to those choices rather than pre-determining them.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_04_A05', 'GOD_04', 'God faces a partly unsettled future and adapts to human choices', 'Open Theism', 'The future is not fully settled because free choices are real, so God adapts and responds as events unfold.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_04_A06', 'GOD_04', 'God cannot coerce events but only lures or persuades the world', 'Process Theism', 'God does not control by force but influences and persuades, and God and the world affect each other over time.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_04_A07', 'GOD_04', 'A distant High God; the material world is flawed or evil', 'Gnosticism', 'The highest God is impersonal and distant from the physical world, which is viewed as flawed or illusory.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('GOD_04_A08', 'GOD_04', 'God created the universe but no longer intervenes in it', 'Deism', 'God created the world and its laws and does not intervene, so events and choices unfold on their own.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_01_A01', 'SCR_01', 'Scripture as the sole infallible rule', 'Sola Scriptura', 'The Bible alone is the final and only completely trustworthy rule that governs all matters of faith and practice.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_01_A02', 'SCR_01', 'Scripture interpreted through a prophetic lens', 'Prophetic Authority', 'The Bible is the final rule, but the writings of a specific, divinely-appointed messenger are essential to correctly interpret its message.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_01_A03', 'SCR_01', 'Scripture and Tradition interpreted by an official office', 'Magisterial Authority', 'Scripture and historic tradition are interpreted authoritatively by the Church’s official, historic teaching office.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_01_A04', 'SCR_01', 'Scripture and Tradition as one inseparable authority', 'Holy Tradition', 'Scripture and the lived tradition of the Church are a single stream of truth; neither is superior to the other, as both emerge from one divine source.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_01_A05', 'SCR_01', 'Scripture as primary, informed by history and reason', 'Consultative Prima Scriptura', 'The Bible is the highest authority, while tradition, reason, and experience are used as necessary tools to help explain and apply its teachings.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_01_A06', 'SCR_01', 'Scripture interpreted by a single governing body', 'Institutional Authority', 'A specific, modern governing organization is the only authorized channel for interpreting the Bible and providing spiritual truth.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_01_A07', 'SCR_01', 'Scripture plus ongoing new revelation', 'Open Canon', 'The Bible is authoritative, but God continues to provide new, binding, and equal revelation through modern apostles or prophets.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_01_A08', 'SCR_01', 'Scripture plus a founder''s foundational writings', 'Dual Authority', 'The Bible and the foundational writings of the community’s founder function together as the authorized rule for faith.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_01_A09', 'SCR_01', 'Scripture guided by immediate inward revelation', 'Inner Light', 'Direct, inward spiritual guidance from God is the primary authority, which clarifies and may even supersede the written word.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_01_A10', 'SCR_01', 'Reason, conscience, and experience as the final test', 'Rationalism', 'Personal reason, moral conscience, and human experience are the final tests used to determine what to believe and how to live.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_01_A11', 'SCR_01', 'Scripture as primary, bound by the early Church’s consensus', 'Patristic Authority', 'Scripture is the supreme authority, but it must be interpreted according to the binding decisions of the early Church''s universal councils and creeds.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_02_A01', 'SCR_02', 'Words dictated directly by God', 'Mechanical Dictation', 'God provided the exact words of the text to human writers who acted as passive instruments to record His speech.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_02_A02', 'SCR_02', 'Words superintended by God through humans', 'Verbal Plenary Inspiration', 'God worked through the personalities and styles of human authors to ensure every word of the original text perfectly conveys His intended message without any error.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_02_A03', 'SCR_02', 'Truthful in spiritual matters but human in details', 'Limited Inerrancy', 'The text is divinely inspired and cannot fail in its purpose of revealing God and salvation, but it may contain human errors in history or science.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_02_A04', 'SCR_02', 'Thoughts inspired by God but wording chosen by humans', 'Conceptual Inspiration', 'God inspired the core concepts and spiritual truths, but left the specific phrasing and historical framing to the human authors.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_02_A05', 'SCR_02', 'A witness that becomes God’s word in encounter', 'Neo-Orthodox Inspiration', 'The text is a unique human witness to divine truth; it is not itself identical to God’s Word, but God speaks through it as people engage with it.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_02_A06', 'SCR_02', 'A human record of religious experience', 'Historical Criticism', 'The text is a fallible human record of spiritual discovery and historical context that serves as a witness to truth despite its errors.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_02_A07', 'SCR_02', 'Human insights enhanced by a spiritual influence', 'Illumination Theory', 'Spiritual influence enhanced the natural wisdom and insights of the writers, much like other great works of religious literature.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_02_A08', 'SCR_02', 'A purely human product with no divine involvement', 'Naturalistic View of Scripture', 'The text is a collection of purely human writings reflecting the culture, politics, and myths of its authors with no divine intervention.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_07_A07', 'SCR_07', 'New Canon-Level Scripture Possible', 'Open Canon', 'God continues to provide new, binding, and authoritative scripture through modern messengers that is equal in authority to the Bible.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_07_A06', 'SCR_07', 'Authoritative prophecy & Gifts continues for the Church', 'Strong Continuationism', 'All spiritual gifts continue, and modern prophecy provides direct and authoritative messages from God that the Church is expected to follow.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_07_A05', 'SCR_07', 'Prophetic gifts continue but are subject to Scripture', 'Continuationism', 'All spiritual gifts continue today, but modern prophecy is fallible and must always be tested against the final authority of the Bible.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_07_A04', 'SCR_07', 'Supernatural insights are possible but rare', 'Cautious Continuationism', 'Extraordinary spiritual manifestations may theoretically occur today, but they are not a normal part of church life and should be viewed with extreme caution.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_07_A03', 'SCR_07', 'Public revelation is closed; private guidance remains', 'Closed Public Revelation', 'The official revelation for the whole Church ended with the first apostles, but God may still grant private guidance or messages to individuals.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_07_A02', 'SCR_07', 'Revelation gifts ceased, but miracles continue', 'Classical Cessationism', 'Miraculous gifts like prophecy and tongues were unique to the apostolic age and have ended, though God still performs direct miracles through prayer.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_07_A01', 'SCR_07', 'All supernatural revelation has ended with the apostles', 'Hard Cessationism', 'All extraordinary spiritual gifts and direct revelatory activity ended after the first apostles; God now works exclusively through the written Word.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_09_A01', 'SCR_09', 'A unique messenger or governing body', 'Prophetic Authority', 'A specific, divinely-commissioned leader or a central organization provides the only binding and authoritative interpretation of the text.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_09_A02', 'SCR_09', 'A living teaching office in historic succession', 'Magisterial Authority', 'A specific, ongoing office of leadership (an official hierarchy) has the exclusive and final power to provide the authentic, binding interpretation of the text for today.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_09_A03', 'SCR_09', 'The universal consensus of the ancient Church', 'Patristic Authority', 'The meaning is found in the historical agreement of the whole Church, as expressed in the ancient councils and the unchanging tradition of the early fathers.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_09_A04', 'SCR_09', 'Established confessions and church office', 'Confessional Sola Scriptura', 'The text interprets itself, but its essential meaning is authoritatively summarized in historic confessions and upheld by the church''s teaching ministry.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_09_A05', 'SCR_09', 'The gathered community together', 'Communal Discernment', 'The meaning of the text is discerned by the local community of believers as they collectively seek the guidance of the Spirit within their specific context.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_09_A06', 'SCR_09', 'The individual believer', 'Individual Interpretation', 'While teachers and traditions are helpful, the individual, guided by the Spirit, is ultimately responsible for interpreting the text’s meaning.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SCR_09_A07', 'SCR_09', 'Human reason and conscience', 'Rationalism', 'The final test of the text''s meaning and relevance is the individual''s own reason and moral conscience, informed by modern knowledge and experience.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_03_A01', 'SAL_03', 'A legal substitution for punishment', 'Penal Substitutionary Atonement', 'Christ’s death was primarily a sacrifice where He bore the specific legal penalty and divine wrath deserved by humanity, satisfying the demands of justice.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_03_A02', 'SAL_03', 'A victory over death and evil powers', 'Christus Victor', 'Christ’s death and resurrection was primarily a triumph that liberated humanity from bondage to death, the devil, and the powers of evil.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_03_A08', 'SAL_03', 'A restoration of God''s offended honor', 'Satisfaction Theory', 'Christ’s death was an offering of infinite value that made satisfaction to God for the insult of human sin, restoring the balance of justice and honor.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_03_A05', 'SAL_03', 'A healing and perfection of human nature', 'Recapitulation Theory', 'Christ’s death was the climax of His life, where He retraced and "re-did" the human experience to heal our nature from within and unite us to God.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_03_A06', 'SAL_03', 'A demonstration to uphold moral order', 'Governmental Theory', 'Christ’s death was not a direct payment for sins, but a public demonstration of the seriousness of sin intended to maintain the integrity of God’s moral government.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_03_A07', 'SAL_03', 'A demonstration of love that inspires change', 'Moral Influence Theory', 'Christ’s death was primarily a supreme display of God’s love intended to soften the human heart, leading individuals to repentance and moral transformation.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_03_A10', 'SAL_03', 'A symbolic or mythic representation of truth', 'Symbolic Atonement', 'Christ’s death is a profound symbol or myth that expresses timeless spiritual truths about sacrifice and renewal, rather than an objective transaction with God.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_06_A01', 'SAL_06', 'God actively decrees both who is saved and who is damned', 'Symmetrical Double Predestination', 'God''s ultimate choice is the direct cause of where everyone ends up; He actively selects certain individuals for salvation and actively selects the rest for damnation, fully determining human choices.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_06_A02', 'SAL_06', 'God elects some to be saved and leaves the rest to their sin', 'Asymmetrical Double Predestination', 'God chooses certain individuals to be saved and ensures they will believe, but He simply passes over the rest, allowing them to follow their own fallen desires and face the consequences.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_06_A03', 'SAL_06', 'God provides sufficient grace to all, but provides special grace to the elect that guarantees free response', 'Efficacious Grace', 'God gives enough grace for anyone to be saved, but He gives a special, highly effective grace to His chosen people that guarantees they will freely and willingly choose to follow Him.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_06_A04', 'SAL_06', 'God gives faith as a pure gift, but humans can reject it', 'Resistible Monergism', 'Salvation is given purely as a gift without any human decision, cooperation, or effort; however, individuals retain the power to actively resist and reject this saving grace.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_06_A05', 'SAL_06', 'God initiates salvation; the weakened human will must actively strive to align with it', 'Synergism', 'The human will, damaged but not destroyed by the fall, retains a natural capacity to respond. Divine grace always initiates and sustains the process, but the individual must exert their own continuous effort to participate in and unite with God''s saving action.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_06_A09', 'SAL_06', 'God restores the will so humans can choose to believe', 'Prevenient Grace', 'People are completely unable to choose God on their own, but God gives a universal grace to everyone that heals the human will just enough so that an individual can make the final choice to believe or reject Him.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_06_A08', 'SAL_06', 'God provides the Gospel, which humans naturally can accept', 'Provisionism', 'Humanity inherently possesses the natural capacity to hear, understand, and believe the Gospel message; no separate, inward "prevenient grace" is required before a person can make the choice.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_06_A10', 'SAL_06', 'God leaves salvation entirely to unassisted human moral effort', 'Absolute Human Autonomy', 'Humanity possesses the complete natural autonomy and moral power to live perfectly and choose the good without any absolute need for special divine grace or intervention.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_07_A01', 'SAL_07', 'A pure gift requiring no human action or response', 'Eternal Justification', 'God declares certain people righteous entirely apart from any human response, including faith; human belief is simply waking up to a status God already granted from eternity.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_07_A02', 'SAL_07', 'A permanent legal declaration through trusting Christ alone', 'Forensic Justification (Eternal Security)', 'God legally declares a person right with Him based solely on their trust in Christ. This standing is a permanent gift that cannot be lost, though genuine trust will naturally lead to a changed life.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_07_A03', 'SAL_07', 'A conditional legal declaration through trusting Christ alone', 'Forensic Justification (Conditional Security)', 'God legally declares a person right with Him based solely on their trust in Christ. However, this standing requires ongoing trust and can be lost if a person entirely abandons the faith.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_07_A07', 'SAL_07', 'A declaration enacted at the moment of water baptism', 'Baptismal Justification', 'God forgives and accepts a person by grace through faith, but this specific legal declaration and spiritual cleansing occurs strictly at the moment of water baptism.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_07_A08', 'SAL_07', 'An inward transformation requiring cooperative love and works', 'Infused Righteousness', 'God does not just legally declare a person right, but actually makes them inwardly righteous through grace. This requires lifelong cooperation, where faith must be expressed in love and good works.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_07_A09', 'SAL_07', 'A progressive healing and union with God''s life', 'Theosis', 'Becoming right with God is not primarily a legal transaction, but a lifelong process of healing human nature and participating in God''s own life and energies.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_07_A10', 'SAL_07', 'A foundational grace completed by strict obedience', 'Covenantal Nomism', 'God provides foundational grace and forgiveness, but ultimate acceptance and justification require a person''s strict obedience to divine commandments, laws, and ordinances.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_07_A12', 'SAL_07', 'A status earned through moral behavior and human effort', 'Moralism', 'A person''s ultimate standing is based primarily on their own good deeds, ethical behavior, and moral self-improvement, without a need for supernatural grace.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_08_A01', 'SAL_08', 'Faith, active love, and participation in the sacraments', 'Sacramental Synergy', 'Salvation requires faith that cooperates with grace through the church''s sacraments, alongside ongoing repentance and good works.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_08_A02', 'SAL_08', 'Faith alone, which is delivered through the sacraments', 'Sacramental Means of Grace', 'Salvation requires only faith, but God specifically creates and delivers this saving faith through the external means of preaching, baptism, and communion.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_08_A03', 'SAL_08', 'Faith alone, with sacraments acting as confirming seals', 'Covenantal Faith', 'Salvation requires only faith; the sacraments do not save, but are commanded by God as visible signs and seals that confirm His promises to the believer.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_08_A09', 'SAL_08', 'Faith, repentance, and essential sacred rites', 'Exaltation to Godhood', 'Salvation and ultimate exaltation require faith, repentance, lifelong obedience to God''s laws, and participation in specific essential ordinances or temple rites.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_08_A04', 'SAL_08', 'Faith, repentance, and water baptism', 'Baptismal Regeneration', 'Salvation requires a person to believe, repent of their sins, and be immersed in water baptism, which is the specific moment forgiveness is granted.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_08_A06', 'SAL_08', 'Personal faith and inward repentance alone', 'Non-Sacramental Sola Fide', 'Salvation requires only a personal, inward decision to trust Christ and repent of sin; all rituals, including baptism, are merely symbolic acts of obedience after salvation.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_08_A08', 'SAL_08', 'Initial faith followed by a life of perseverance', 'Conditional Security', 'Salvation requires a person to initially believe and repent, but they must also continually persevere in faith and obedient living to the end of their life to remain saved.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_08_A05', 'SAL_08', 'Nothing; salvation is exclusively God''s independent action', 'Hyper-Calvinism', 'Human beings do not and cannot do anything to be saved; salvation is entirely a sovereign act of God applied to His people without requiring human conditions or decisions.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_08_A11', 'SAL_08', 'Following the inner divine light', 'Inner Light', 'Salvation is realized by turning inward to listen to and obey the divine light or spirit present within all people, leading to a life of righteous action.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_08_A12', 'SAL_08', 'Living an ethical and compassionate life', 'Universal Moralism', 'Salvation is ultimately universal or achieved through moral living; being a loving, ethical person matters more than performing religious rituals or holding specific doctrinal beliefs.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_14_A01', 'SAL_14', 'Yes, conscious faith in Christ during this life is strictly required', 'Strict Exclusivism', 'Salvation is exclusively found through explicit, conscious faith in Jesus Christ before death; no other path or post-mortem opportunity exists.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_14_A05', 'SAL_14', 'Yes, but those who never hear the Gospel may accept it after death', 'Post-Mortem Evangelization', 'Explicit faith in Jesus Christ is the absolute requirement for salvation, but God provides an opportunity in the afterlife for those who died without a fair chance to hear and accept the message.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_14_A02', 'SAL_14', 'Christ is the only Savior, but His grace may reach those who do not know Him', 'Inclusivism', 'Jesus is the only source of salvation, but God''s mercy may mysteriously extend to those who, through no fault of their own, do not explicitly know Christ but sincerely seek God and live according to their conscience.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_14_A06', 'SAL_14', 'Christ is the only Savior, and He will ultimately save everyone', 'Christian Universalism', 'Jesus is the sole source of salvation, and His redemptive work is so complete that He will eventually draw all human beings to Himself, resulting in the ultimate reconciliation of everyone.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_14_A03', 'SAL_14', 'No, Jesus is one of many equally valid paths to God', 'Religious Pluralism', 'Jesus Christ is the distinct path for Christians, but other world religions and spiritual traditions provide equally valid, independent paths to God and ultimate salvation.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAL_14_A04', 'SAL_14', 'Salvation is an inner spiritual awakening, not exclusive to Jesus', 'Metaphysical Salvation', 'Salvation is achieved through spiritual enlightenment, metaphysical understanding, or realizing one''s inner divinity, rather than relying on the historical person or work of Jesus.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_01_A01', 'CHR_01', 'A visible, global institution and mystical body', 'Institutional Ecclesiology', 'The Church is a single, visible, worldwide society that was historically established by Christ and serves as His mystical body on earth.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_01_A02', 'CHR_01', 'A communion of sacramental communities', 'Eucharistic Ecclesiology', 'The Church is fundamentally a sacramental and eucharistic communion; it is fully present wherever the local community gathers around the Eucharist in historic succession.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_01_A03', 'CHR_01', 'The assembly where the Word and Sacraments are pure', 'Confessional Ecclesiology', 'The true Church exists wherever the Gospel is purely preached and the holy sacraments are administered according to Christ''s institution.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_01_A04', 'CHR_01', 'The visible covenant community of God', 'Covenantal Ecclesiology', 'The Church is the visible covenant family of God throughout the world, consisting of all those who profess the true religion, together with their children.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_01_A08', 'CHR_01', 'An exclusively restored divine organization', 'Restorationism', 'The true Church was lost to apostasy for centuries but has been exclusively restored by God in the modern era with reinstated divine truth and authority.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_01_A05', 'CHR_01', 'A gathered, voluntary community of true believers', 'Believers'' Church', 'The visible Church is fundamentally a gathered community consisting exclusively of individuals who have personally believed, been baptized, and covenanted together.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_01_A07', 'CHR_01', 'A community organized for social justice and healing', 'Social Gospel', 'The Church is primarily a prophetic community of Jesus-followers organized to enact social justice, pursue peace, and bring about earthly renewal.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_01_A06', 'CHR_01', 'The invisible, spiritual fellowship of all true believers', 'Invisible Ecclesiology', 'The true Church is not a visible earthly organization or denomination, but the unseen, spiritual body of all genuine believers known only to God.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_09_A01', 'CHR_09', 'Yes, an unbroken chain of bishops is required', 'Tactile Apostolic Succession', 'A true church requires bishops who have been ordained in an unbroken, historic physical line from the original apostles to guarantee valid sacraments and authority.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_09_A02', 'CHR_09', 'Yes, it is the historic norm, though God may work outside it', 'Normative Historic Episcopate', 'The historic succession of bishops is the normal and expected structure for the church, though God''s grace can still operate in communities lacking this unbroken chain.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_09_A07', 'CHR_09', 'No, true authority was lost and had to be restored', 'Restorationism', 'The historic chain of authority was completely broken by apostasy, so valid church authority had to be restored directly by God through new messengers.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_09_A03', 'CHR_09', 'It is a beneficial historic sign, but not strictly necessary', 'Beneficial Historic Episcopate', 'Maintaining a historic line of bishops is a valuable sign of unity and historical continuity, but a church is fully valid and real without it.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_09_A05', 'CHR_09', 'No, succession is carried by faithful doctrine and an ordered ministry', 'Ministerial Succession', 'Apostolic continuity is not a physical chain of bishops, but the faithful transmission of the apostles'' teaching through an officially ordained, interconnected ministry.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_09_A06', 'CHR_09', 'No, an unbroken line of human leaders is irrelevant', 'Free Church Ecclesiology', 'The validity of a church does not depend on any historical chain of bishops or clergy. A true church is validated solely by its present faithfulness to Christ and the Spirit.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_10_A04', 'CHR_10', 'Christ mediates through a uniquely restored earthly priesthood', 'Restored Sacerdotalism', 'Christ is the ultimate mediator, but receiving His saving covenants requires the authority of a uniquely restored earthly priesthood; departed saints do not intercede for us.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_10_A01', 'CHR_10', 'Christ uniquely mediates, but through the ordained priesthood and heavenly saints', 'Participatory Mediation', 'Christ is the one mediator, but He distributes His saving grace through the Church''s earthly ordained priesthood and welcomes the intercessory prayers of the departed saints.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_10_A02', 'CHR_10', 'Christ mediates alone, ordinarily through the Church''s earthly ministry', 'Ministerial Dispensation', 'Christ is the sole mediator and ordinarily delivers His grace through the Church''s earthly ministry of Word and Sacrament, but departed saints are not invoked.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_10_A03', 'CHR_10', 'Christ alone mediates; every believer has direct access', 'Direct Access to God', 'Jesus Christ is the sole mediator; every believer has immediate, direct access to God without any need for intervening earthly priests, institutional structures, or departed saints.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_10_A05', 'CHR_10', 'Direct, unmediated inner spiritual communion', 'Inner Light', 'Every person has direct access to the Divine through inward spiritual communion, making external mediators, clergy, and physical religious structures unnecessary.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_13_A01', 'CHR_13', 'No, all formal leadership and teaching roles are reserved for men', 'Strict Complementarianism', 'The formal offices of the church and all official teaching or directorial roles are reserved exclusively for men; women do not hold official ministry titles or public teaching positions.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_13_A06', 'CHR_13', 'No, but women may lead and teach in specific, unordained roles', 'Broad Complementarianism', 'Governing offices and the public teaching of men are reserved for men, but women may hold recognized, unordained roles directing ministries or teaching other women and children.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_13_A02', 'CHR_13', 'Women may be ordained as deacons, but not as pastors or priests', 'Female Diaconal Ordination', 'Women may be formally ordained to the diaconate to serve the church, but the primary teaching, sacramental, and governing offices are reserved for men.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_13_A04', 'CHR_13', 'Women may be ordained, but not to the highest governing office', 'Soft Complementarianism', 'Women may be ordained to pastoral or teaching roles (e.g., associate pastor or priest), but the position of highest hierarchical authority (such as Senior Pastor / Elder or Bishop) is reserved for men.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_13_A07', 'CHR_13', 'The church does not ordain formal clergy of either gender', 'Non-Clerical Egalitarianism', 'The church rejects the concept of a formal, ordained clergy class altogether; spiritual leadership and public ministry are shared equally among all believers regardless of gender.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('CHR_13_A05', 'CHR_13', 'Yes, women may be ordained to any and all offices', 'Full Egalitarianism', 'Women may be ordained to every level of church leadership available, including the highest hierarchical or teaching offices, with absolutely no restrictions based on gender.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAC_02_A01', 'SAC_02', 'It is a means of grace that directly causes new birth and washes away sin', 'Baptismal Regeneration', 'God uses the physical rite of water baptism as the instrumental means to forgive sins, infuse grace, and effect spiritual regeneration.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAC_02_A06', 'SAC_02', 'It is the specific moment a repentant believer receives formal pardon', 'Ordinance of Remission', 'While having no mystical power itself and meriting nothing, immersion is the formal, specific means by which a repentant believer receives God''s absolution and release from guilt.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAC_02_A02', 'SAC_02', 'It is a visible sign and seal of God''s covenant promises', 'Covenantal Sign and Seal', 'It acts as a visible pledge that grafts a person into the visible church and confirms God''s promises, but the physical act itself does not automatically guarantee inward regeneration.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAC_02_A03', 'SAC_02', 'It is a symbolic public testimony of a salvation already received', 'Memorialism', 'The rite is purely an outward symbol of an inward reality. It acts as a public profession of faith and an act of obedience, but conveys no saving grace itself.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAC_02_A04', 'SAC_02', 'It is a meaningful community ritual, but not spiritually necessary', 'Optional Ritual', 'Water baptism may hold personal meaning or signify inclusion in a community, but it is not a requirement for salvation or spiritual life.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAC_02_A05', 'SAC_02', 'Water baptism is unnecessary; true baptism is purely inward', 'Inward Baptism', 'The physical rite of water baptism is rejected or viewed as entirely unnecessary; the only true and essential baptism is the inward, spiritual baptism by God.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAC_03_A01', 'SAC_03', 'Infants of believers and unbaptized converts', 'Paedobaptism', 'Baptism is properly administered to the infants of church members, as well as to adults who are converting to the faith.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAC_03_A03', 'SAC_03', 'Only those who personally profess faith', 'Credobaptism', 'Baptism is strictly reserved for individuals of any age who are capable of making a personal, conscious profession of faith and repentance.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAC_03_A04', 'SAC_03', 'Children at the age of accountability and adult converts', 'Age of Accountability', 'Infant baptism is rejected, but children are expected to be baptized once they reach a recognized age of moral accountability, alongside adult converts.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('SAC_03_A05', 'SAC_03', 'No one; physical water baptism is not practiced', 'Inward Baptism', 'The community does not practice physical water baptism for anyone, focusing exclusively on an inward or spiritual baptism.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_05_A01', 'WOR_05', 'Worship must be strictly reverent and objective', 'Objective Solemnity', 'Worship focuses entirely on solemn reverence and biblical truth. Outward emotional displays are discouraged, and the focus is on duty and the mind rather than the feelings.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_05_A02', 'WOR_05', 'Emotions are a valid response, but truth and order must lead', 'Regulative Principle of Order', 'Worship is centered on the objective teaching of truth and an orderly service. Personal feelings are natural and welcome, but they do not dictate or drive how the worship is conducted.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_05_A03', 'WOR_05', 'Heartfelt sincerity within a structured service', 'Pietism', 'True worship requires deep, personal, internal conviction and warmth. While emotional sincerity is highly valued, the service itself remains organized, planned, and orderly.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_05_A04', 'WOR_05', 'Highly vocal and physically expressive worship', 'Revivalism', 'Worship is energetic and outwardly expressive. Practices like shouting, weeping, dancing, clapping, or vocal responses are normal, expected ways to passionately praise God.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_05_A07', 'WOR_05', 'Seeking a tangible, supernatural manifestation', 'Charismatic Encounter', 'The primary goal is for the Holy Spirit to tangibly move in the room. Worship is intentionally flexible to allow for spontaneous spiritual gifts like prophecy, physical healing, or speaking in tongues.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_05_A06', 'WOR_05', 'Unplanned reliance on spontaneous inner promptings', 'Unprogrammed Worship', 'Worship completely abandons planned structures, songs, or leaders. The community waits in stillness until the Spirit directly prompts someone to speak, pray, or act.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_06_A06', 'WOR_06', 'Both flat images and statues are honored and used for devotion', 'Comprehensive Iconodulism', 'Paintings, icons, and three-dimensional statues are all warmly embraced and actively used as focal points for prayer, honor, and devotion.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_06_A05', 'WOR_06', 'Flat images are honored and venerated, but statues are avoided', 'Restricted Iconodulism', 'Flat images (icons) are essential to worship and are actively honored (e.g., kissed or given incense), but three-dimensional statues are avoided in the sanctuary.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_06_A04', 'WOR_06', 'Images are helpful tools to focus the mind during prayer', 'Didactic Iconism', 'Art, such as crucifixes or paintings, are intentionally placed in worship spaces as valuable tools to help focus the mind on Christ, though they are not physically venerated.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_06_A02', 'WOR_06', 'Visual depictions should be kept out of the worship space', 'Sanctuary Aniconism', 'Images may exist for education outside the church, but the sanctuary itself should be plain and free of visual depictions of the divine to avoid distraction.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_06_A01', 'WOR_06', 'All religious images of the divine must be strictly avoided', 'Strict Iconoclasm', 'Any visual depiction of God or Jesus should be strictly avoided everywhere—both in church and at home—as they inherently violate the commandment against idolatry.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_06_A03', 'WOR_06', 'Art is acceptable as decoration, but not as an aid for prayer', 'Non-Devotional Ornamentation', 'Visual art and crosses are acceptable as background decoration or teaching tools, but they should never be used as a focal point for prayer or devotion.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_08_A07', 'WOR_08', 'Active today, flowing freely and ecstatically', 'Neo-Pentecostalism', 'Spiritual gifts are actively expected and practiced freely with minimal formal oversight, prioritizing spontaneous, ecstatic encounters with the Spirit.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_08_A06', 'WOR_08', 'Active today, with tongues highly emphasized', 'Classical Pentecostalism', 'All gifts continue, and speaking in tongues is highly emphasized as the essential, initial physical evidence of the baptism in the Holy Spirit.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_08_A04', 'WOR_08', 'Active today, but practiced with careful order', 'Third Wave Continuationism', 'All spiritual gifts continue and should be desired, but they must be carefully evaluated and practiced with structured biblical order in worship.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_08_A02', 'WOR_08', 'Not actively expected, but God may still act', 'Soft Cessationism', 'While God still heals and performs miracles, the specific supernatural gifts of prophecy and tongues are not expected or pursued as regular ministries today.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_08_A01', 'WOR_08', 'They ended with the apostles', 'Hard Cessationism', 'These specific miraculous gifts were uniquely given to authenticate the early church and have completely ceased today.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_17_A01', 'WOR_17', 'Born without sin, Mother of God, ever-virgin, and prayed to', 'Immaculate Conception', 'She was miraculously preserved from all sin from conception, is the Mother of God, remained a virgin forever, and is actively invoked in prayer.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_17_A02', 'WOR_17', 'Born with original sin, Mother of God, ever-virgin, and prayed to', 'Orthodox Mariology', 'She is the Mother of God and remained a virgin forever, and we ask for her prayers, but she was born with standard human limits (ancestral sin).');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_17_A03', 'WOR_17', 'Mother of God and ever-virgin, but not prayed to', 'Non-Devotional Perpetual Virginity', 'She is the Mother of God (since Jesus is divine) and remained a virgin her whole life, but she should not be prayed to or treated as a mediator.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_17_A04', 'WOR_17', 'Mother of God, but had other children and is not prayed to', 'Protestant Theotokos', 'She is the Mother of God (because Jesus is fully divine), but she later had other children naturally with Joseph, and we do not pray to her.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_17_A05', 'WOR_17', 'Mother of the human Jesus only, ever-virgin, and honored in liturgy', 'Nestorian Mariology', 'She is the mother of the human Messiah, not the "Mother of God." She remained a virgin forever and is honored and invoked in the church''s liturgy.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_17_A06', 'WOR_17', 'Mother of the human Jesus only, had other children, and no prayer', 'Low-Church Anti-Marianism', 'She is simply the earthly mother of Jesus, not the "Mother of God." She later had other children normally, and we do not pray to her or elevate her.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_17_A07', 'WOR_17', 'A vessel for a heavenly body; she did not provide Jesus flesh', 'Celestial Flesh Christology', 'Jesus brought His physical body from heaven and merely passed through her like water through a pipe, meaning she did not provide His human flesh.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_17_A09', 'WOR_17', 'A natural human mother; the virgin birth is not literal', 'Psilanthropism', 'She was a virtuous historical woman who conceived Jesus naturally with a human father; the virgin birth is a theological legend or metaphor.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_18_A01', 'WOR_18', 'Powerful patrons who directly grant miracles and favors', 'Folk Veneration', 'They are potent spiritual patrons who can directly provide protection, healings, and earthly favors in response to rituals and devotion.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_18_A02', 'WOR_18', 'Honored members of the Church who intercede for us', 'Veneration of Saints', 'They are alive in Christ, actively interceding for the world, and should be highly honored and asked for their prayers just like living believers on earth.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_18_A03', 'WOR_18', 'We may ask for their prayers, but it is not required', 'Permissible Invocation', 'It is permissible to privately ask them to pray for us, as they are alive in Christ, but this is a personal devotion and not a required practice.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_18_A04', 'WOR_18', 'Conscious in God''s presence and inspiring, but we pray only to Him', 'Historical Commemoration', 'The departed saints are consciously alive in heaven and serve as inspiring examples of faith, but directing prayers to them is inappropriate because prayer is an act of worship reserved exclusively for God.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('WOR_18_A05', 'WOR_18', 'Unconscious in death and awaiting the resurrection', 'Christian Mortalism', 'The dead are completely unconscious (asleep) until the future bodily resurrection. Because they are not currently active or awake in heaven, they cannot hear prayers or interact with the living.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_02_A01', 'ESC_02', 'Yes, removed entirely before a future tribulation', 'Pre-Tribulationism', 'Believers will be physically caught up to heaven to escape a literal, future seven-year period of global tribulation before Christ returns to earth.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_02_A05', 'ESC_02', 'Yes, removed during a future tribulation', 'Mid-Tribulationism', 'Believers will endure the first part of a future literal tribulation (the wrath of man/Antichrist) but will be caught up before God pours out His ultimate wrath.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_02_A02', 'ESC_02', 'No, the Church endures the entire future tribulation', 'Post-Tribulationism', 'Believers will remain on earth throughout a future literal period of great tribulation, being caught up to meet Christ only at His final, visible return.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_02_A06', 'ESC_02', 'No, the "Great Tribulation" already occurred in the past', 'Partial Preterism', 'The period of great tribulation described in the New Testament was largely fulfilled in the first century (e.g., the destruction of Jerusalem). The Church now awaits only a single, final return.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_02_A03', 'ESC_02', 'No, tribulation is the ongoing experience of the Church', 'Amillennialism', 'There is no distinct future 7-year tribulation or secret rapture. The Church experiences tribulation throughout history and awaits a single, simultaneous return and resurrection.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_02_A04', 'ESC_02', 'No, these accounts are entirely symbolic', 'Symbolic Eschatology', 'The concepts of a "rapture" and "tribulation" are ancient metaphors for spiritual struggles, political liberation, or the triumph of good over evil, not literal historical events.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_06_A04', 'ESC_06', 'Entrance into a temporary spirit world for learning and service', 'Intermediate Spirit World', 'Spirits enter a temporary realm to continue learning, progress, and serve as missionaries to those who did not hear the truth on earth.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_06_A06', 'ESC_06', 'Reincarnation into a new earthly life', 'Christian Reincarnation', 'The soul passes into another earthly body to continue its spiritual evolution, learn new lessons, or pay off karmic debt.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_06_A02', 'ESC_06', 'Immediate judgment, followed by heaven or temporary purification', 'Purgatorial Purification', 'The soul undergoes a particular judgment and either enters heaven immediately or undergoes a temporary period of purification to achieve the holiness necessary for heaven.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_06_A07', 'ESC_06', 'A spiritual journey to a foretaste of heaven, aided by the Church', 'Aerial Toll Houses', 'The soul embarks on a spiritual journey of testing (often described as passing through aerial toll houses), heavily aided by the prayers of the living, before entering a conscious foretaste of final joy.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_06_A01', 'ESC_06', 'Immediate, conscious presence with God in heaven', 'Immediate Conscious Presence', 'The soul separates from the body and immediately enters into the conscious, joyful presence of the Lord, requiring no further purification, while awaiting the bodily resurrection.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_06_A03', 'ESC_06', 'Unconscious sleep until the bodily resurrection', 'Christian Mortalism', 'The dead enter a state of total unconsciousness, knowing nothing and experiencing no passage of time, until God resurrects them at the end of the age.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_06_A05', 'ESC_06', 'Consciousness ends; believers live on in God''s memory and earthly legacy', 'Objective Immortality', 'Personal consciousness ends permanently at death. ""Eternal life"" refers to a person''s enduring legacy on earth and their objective existence within the eternal memory of God.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_07_A01', 'ESC_07', 'A state of eternal, conscious separation and suffering', 'Eternal Conscious Torment', 'The unrepentant experience a definitive, unending state of conscious separation from God and endure eternal consequences for their sins.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_07_A02', 'ESC_07', 'Complete destruction and cessation of existence', 'Annihilationism', 'The unrepentant do not suffer eternally; rather, they face the capital punishment of the soul, resulting in their complete and permanent destruction (non-existence).');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_07_A05', 'ESC_07', 'Temporary suffering followed by a lesser degree of glory', 'Degrees of Glory', 'Most of the wicked will suffer temporarily for their sins, but will ultimately be redeemed into a lesser kingdom of heavenly glory, while only a very few suffer eternal perdition.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_07_A03', 'ESC_07', 'A temporary, remedial state leading to ultimate salvation', 'Universal Reconciliation', 'Hell is not eternal punishment, but a temporary, purifying fire designed to correct and cleanse the wicked, ultimately leading to the reconciliation of all people to God.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ESC_07_A04', 'ESC_07', 'A metaphor for present earthly or psychological suffering', 'Symbolic Eschatology', 'Hell is not a literal afterlife destination, but a symbolic way of describing the present spiritual, psychological, or sociological alienation humans experience in this life.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_01_A01', 'ETH_01', 'The direct commands and precepts of the Bible alone', 'Strict Biblicism', 'Moral authority resides solely in the explicit commands and principles found in Scripture, which provide a sufficient guide for every ethical situation.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_01_A02', 'ETH_01', 'An innate moral order and conscience, guided by the Church', 'Natural Law Tradition', 'God has embedded a universal moral order into human nature that can be known by reason. This conscience guides decisions, with Scripture and authoritative Church teaching providing necessary illumination.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_01_A08', 'ETH_01', 'The biblical moral law, guided by historic confessions', 'Confessional Ethics', 'Ethical decisions are based on Scripture’s moral law (such as the Ten Commandments), interpreted through the lens of historic creeds and confessional standards.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_01_A04', 'ETH_01', 'The direct, inward leading of the Holy Spirit', 'Pneumatic Illumination', 'Ethical decisions are ultimately guided by immediate personal revelation, conscience, or the inward leading of the Spirit in the given moment.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_01_A03', 'ETH_01', 'Scriptural principles applied through reason and experience', 'Ethical Prima Scriptura', 'Scripture is the primary source, but its ethical principles must be practically applied through the necessary lenses of tradition, human reason, and lived experience.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_01_A07', 'ETH_01', 'The teachings of Jesus, discerned by the local community', 'Communal Discernment', 'Ethical decisions are rooted in the direct teachings of Jesus (like the Sermon on the Mount) and discerned collectively by the gathered community of believers for their specific context.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_01_A06', 'ETH_01', 'The overarching principles of love, justice, and harm reduction', 'Situation Ethics', 'Specific ancient biblical rules are secondary to the broader, universal ethical mandates of love, inclusion, and pursuing justice in modern society.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_05_A01', 'ETH_05', 'Six literal days and a recent, young creation', 'Young Earth Creationism', 'The universe and humanity were created by God in six literal 24-hour days approximately 6,000 to 10,000 years ago, even if the earth was created with the appearance of age.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_05_A02', 'ETH_05', 'An old universe with a recent six-day restoration', 'Gap Creationism', 'A vast expanse of time exists between the first two verses of Genesis, containing an ancient ruined earth, followed by a recent, literal six-day re-creation.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_05_A03', 'ETH_05', 'An old universe with direct, special acts of creation', 'Progressive Creationism', 'The universe is ancient, but God intervened directly to create different life forms. Genesis is read as long eras (Day-Age), but macro-evolution and common descent are rejected.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_05_A04', 'ETH_05', 'An inspired theological framework, not a science book', 'Literary Framework View', 'The creation accounts are brilliant, divinely inspired literary structures designed to convey theological truths about God, humanity, and order, leaving the actual scientific mechanism of origins open.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_05_A05', 'ETH_05', 'God planned or guided the process of evolution', 'Theistic Evolution', 'The universe is ancient, and God used the natural processes of evolution to bring about life. The Genesis days are understood figuratively, either as long geological eras or literary devices.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_05_A06', 'ETH_05', 'Unguided evolution; the text is purely human myth', 'Naturalistic Evolution', 'Humanity and the universe arose entirely through natural, unguided evolutionary processes; the Genesis accounts are purely human, ancient mythological attempts to understand origins, devoid of divine inspiration.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_06_A01', 'ETH_06', 'Absolute refusal of violence and military service', 'Christian Pacifism', 'Christians are strictly prohibited from using lethal force or participating in the military, trusting entirely in the ethic of enemy-love and non-resistance.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_06_A06', 'ETH_06', 'Military service is permitted, but only as non-combatants', 'Non-Combatancy', 'Military service is permissible to aid one''s country, but Christians must strictly refuse to bear arms or use lethal force (e.g., serving as medics or cooks).');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_06_A05', 'ETH_06', 'A personal decision based on individual conscience', 'Liberty of Conscience', 'The church does not enforce a strict dogma on warfare; serving in the military or refusing to do so is a matter of individual liberty and personal conviction before God.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_06_A02', 'ETH_06', 'Permissible only under strict conditions of justice', 'Just War Theory', 'War is a grave matter but is morally permissible—and sometimes obligatory—if authorized by a legitimate government for a just cause, as a last resort, and fought justly.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_06_A04', 'ETH_06', 'A tragic but necessary evil to restrain greater evil', 'Christian Realism', 'Violence is always contrary to the ideal of love, but in a fallen world, military force is sometimes a tragic necessity to protect the innocent and restrain tyranny.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_06_A03', 'ETH_06', 'A divinely commanded holy war to defeat God''s enemies', 'Divine Militarism', 'God can actively command and bless aggressive warfare to destroy evil and advance His kingdom on earth.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_09_A01', 'ETH_09', 'Both the attraction itself and the acts are inherently sinful', 'Strict Prohibition (Side X)', 'Same-sex attraction is not merely a temptation, but a culpable sin of the heart. Individuals are called to repent of these desires and seek total transformation or deliverance.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_09_A04', 'ETH_09', 'All sexual intimacy and marriage are prohibited for everyone', 'Universal Celibacy', 'The church mandates absolute celibacy for all members; all sexual relations and marriages are entirely prohibited for everyone, regardless of orientation.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_09_A02', 'ETH_09', 'The attraction is a non-sinful temptation, but the acts are sinful', 'Traditional Chastity (Side Y)', 'Same-sex attraction is a disordered inclination or trial, but it is not a sin unless acted upon. Sexual acts are strictly prohibited, and individuals are called to a life of chastity.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_09_A07', 'ETH_09', 'Celibate partnerships allowed; sexual acts and marriage prohibited', 'Covenanted Celibacy (Side B)', 'Individuals may enter into committed, socially romantic partnerships or civil unions. However, same-sex sexual acts and the sacrament of Holy Matrimony remain strictly prohibited.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_09_A05', 'ETH_09', 'Civil unions may be blessed, but formal marriage is male-female only', 'Pastoral Accommodation', 'The church may pastorally bless same-sex unions and leave sexual ethics to individual conscience, but the official religious rite of Holy Matrimony is restricted to male-female couples.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_09_A06', 'ETH_09', 'Marriage is fully permitted for laity, but clergy are restricted', 'Differentiated Inclusion', 'The church performs same-sex marriages for its lay members, but holds its ordained clergy to a different traditional standard, requiring them to be celibate or in male-female marriages.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('ETH_09_A03', 'ETH_09', 'Full equality; same-sex marriage and ordination are fully affirmed', 'Full Affirming Theology', 'The church fully affirms same-sex relationships, performing marriages and ordaining individuals without any restrictions or distinct tiers of membership based on sexual orientation.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_03_A06', 'MET_03', 'Material science is irrelevant; ultimate truth is purely spiritual', 'Fideism', 'The physical world or secular science is fundamentally flawed, fallen, or illusory; true knowledge comes exclusively through divine spiritual revelation, making scientific conflicts irrelevant.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_03_A01', 'MET_03', 'The Bible is scientifically and historically accurate as written', 'Biblical Inerrancy', 'The Bible contains no errors in history or science; any conflict arises because modern secular scientific theories are flawed or misinterpret the evidence.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_03_A02', 'MET_03', 'The Bible and science are both true and must be harmonized', 'Concordism', 'God is the author of both nature and Scripture. Conflicts are resolved by adjusting our interpretation of the biblical text to harmonize with established scientific facts.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_03_A03', 'MET_03', 'The Bible teaches faith perfectly, using ancient concepts and worldview', 'Accommodationism', 'The Bible is completely trustworthy in matters of faith and salvation, but God accommodated His message by using the ancient, pre-scientific worldview of the human authors to communicate.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_03_A04', 'MET_03', 'The Bible contains human errors and requires critical study', 'Historical Criticism', 'Because the Bible is a human record, it contains historical and scientific errors; we must use modern critical scholarship and reason to discern its core spiritual message.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_03_A05', 'MET_03', 'The accounts are purely symbolic metaphors, not literal history', 'Existential Hermeneutic', 'The biblical narratives are not literal history or science; they are profound symbolic myths designed to express spiritual, moral, or existential truths.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_04_A02', 'MET_04', 'Believing and upholding orthodox doctrine and true worship', 'Confessionalism', 'The Christian life is fundamentally about intellectual and spiritual fidelity to the truth, focusing on correct biblical doctrine, confessional orthodoxy, and proper worship.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_04_A01', 'MET_04', 'Receiving grace through the Church''s sacramental life', 'Sacramentalism', 'The Christian life is primarily about participating in the objective, historical rites of the Church, receiving God''s grace through the liturgy and sacraments.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_04_A06', 'MET_04', 'Separating from worldly corruption to pursue strict holiness', 'Fundamentalist Separatism', 'The Christian life is a call to come out from the world, maintaining strict moral purity, distinct living, and separation from secular culture and compromised religion.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_04_A08', 'MET_04', 'Embodying the peaceful, counter-cultural reign of God on earth', 'Kingdom Theology', 'The ultimate purpose of the Christian life is not just individual salvation, but gathering as a distinct community that visibly embodies the peace, ethics, and reign of God to the world.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_04_A05', 'MET_04', 'Transforming society through acts of justice and systemic change', 'Liberation Theology', 'The Christian life is primarily about building a better world by enacting justice, showing mercy to the marginalized, and transforming oppressive societal structures.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_04_A03', 'MET_04', 'Knowing Jesus personally and making disciples of all nations', 'Missional Evangelicalism', 'The Christian life is driven by a heartfelt, personal relationship with Jesus Christ, which naturally overflows into an active mission to evangelize and make disciples globally.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_04_A04', 'MET_04', 'Experiencing and ministering the supernatural power of the Spirit', 'Pentecostalism', 'The Christian life is fundamentally a dynamic, experiential reality focused on being empowered by the Holy Spirit to witness, heal, prophesy, and defeat spiritual darkness.');
INSERT OR REPLACE INTO answer_options (id, question_id, answer_text, theological_label, description) VALUES ('MET_04_A07', 'MET_04', 'Seeking direct, unmediated union with the Divine', 'Contemplative Mysticism', 'The Christian life is an inward journey of the soul, focusing on silence, contemplation, and seeking a direct, experiential union with God beyond words or earthly structures.');

